// ============================================================================
// Stripe Webhook Handler (MUST BE BEFORE express.json())
// ============================================================================
app.post('/stripe/webhook',
  express.raw({ type: 'application/json' }),
  async (req, res) => {
    if (!stripe) {
      console.error('❌ Stripe not initialized');
      return res.status(400).send('Stripe not configured');
    }
    
    if (!STRIPE_WEBHOOK_SECRET) {
      console.warn('⚠️  STRIPE_WEBHOOK_SECRET not set. Webhook verification disabled.');
      return res.status(400).send('Webhook secret not configured');
    }
    
    const sig = req.headers['stripe-signature'];
    let event;
    
    try {
      event = stripe.webhooks.constructEvent(
        req.body,
        sig,
        STRIPE_WEBHOOK_SECRET
      );
    } catch (err) {
      console.error(`❌ Webhook signature verification failed: ${err.message}`);
      return res.status(400).send(`Webhook Error: ${err.message}`);
    }
    
    try {
      switch (event.type) {
        case 'checkout.session.completed': {
          const session = event.data.object;
          // ✅ Get email from multiple sources (customer_email or customer_details)
          const email = (session.customer_email || session.customer_details?.email || "").trim().toLowerCase();
          const customerId = session.customer;
          const subscriptionId = session.subscription;
          const plan = String(session.metadata?.plan || 'basic').toLowerCase();
          const salerId = String(session.metadata?.salerId || session.metadata?.saler_id || "").trim();
          
          console.log(`\n📧 [WEBHOOK] checkout.session.completed`);
          console.log(`   Email: ${email}`);
          console.log(`   Plan: ${plan}`);
          console.log(`   Customer ID: ${customerId}`);
          console.log(`   Subscription ID: ${subscriptionId}`);
          if (salerId) {
            console.log(`   💰 Saler referral: ${salerId}`);
          }
          
          if (!email) {
            console.error('❌ Webhook: No email found in session');
            console.error('   Session data:', JSON.stringify({
              customer_email: session.customer_email,
              customer_details: session.customer_details,
              customer: session.customer
            }));
            break;
          }
          
          const user = await getUserByEmail(email);
          if (user) {
            const now = Date.now();
            
            // ✅ Determine subscription duration based on plan
            let durationDays = 30; // default monthly
            const planLower = plan.toLowerCase();
            
            // Check if annual plan (350 = annual, 12 months)
            if (planLower.includes('annual') || planLower.includes('year') || planLower.includes('350')) {
              durationDays = 365;
            }
            
            const paidUntilMs = now + (durationDays * 24 * 60 * 60 * 1000);
            
            // Map plan to tier (handle various plan name formats)
            let tier = plan.toUpperCase();
            if (planLower.includes('verified') || planLower.includes('trial') || planLower.includes('4.95')) {
              tier = 'VERIFIED';
            } else if (planLower.includes('daytrader') || planLower.includes('35.99')) {
              tier = 'DAYTRADER';
            } else if (planLower.includes('swing') || planLower.includes('45.99')) {
              tier = 'SWING';
            } else if (planLower.includes('pro') || planLower.includes('55.99')) {
              tier = 'PRO';
            } else if (planLower.includes('annual') || planLower.includes('350')) {
              tier = 'ANNUAL';
            }
            
            const updateData = {
              tier,
              
              // ✅ WRITE BOTH forms (snake + camel) to avoid mapping bugs
              is_paid: 1,
              isPaid: true,
              
              paid_until: paidUntilMs,
              paidUntil: paidUntilMs,
              
              stripe_customer_id: customerId,
              stripeCustomerId: customerId,
              
              stripe_subscription_id: subscriptionId,
              stripeSubscriptionId: subscriptionId,
            };
            
            // Save salerId if provided (only on first purchase, don't overwrite)
            if (salerId && !user.saler_id) {
              updateData.saler_id = salerId;
              updateData.salerId = salerId;
            }
            
            await updateUser(user.id, updateData);
            
            console.log(`✅ User ${email} upgraded to ${tier}`);
            console.log(`   - Duration: ${durationDays} days`);
            console.log(`   - Expires: ${new Date(paidUntilMs).toISOString()}`);
            console.log(`   - is_paid: 1, paid_until: ${paidUntilMs}`);
            if (salerId && !user.saler_id) {
              console.log(`   - saler_id saved: ${salerId}`);
            }
          } else {
            console.warn(`⚠️  Checkout completed for unknown email: ${email}`);
            console.warn(`   This user needs to log in with Google first to create an account`);
          }
          break;
        }
        
        case 'customer.subscription.updated':
        case 'customer.subscription.deleted': {
          const subscription = event.data.object;
          const customerId = subscription.customer;
          const user = await getUserByStripeCustomerId(customerId);
          
          if (user) {
            const isActive = subscription.status === 'active';
            const paidUntil = subscription.current_period_end * 1000;
            
            // ✅ WRITE BOTH forms (snake + camel) to avoid mapping bugs
            await updateUser(user.id, {
              is_paid: isActive ? 1 : 0,
              isPaid: isActive,
              
              paid_until: isActive ? paidUntil : 0,
              paidUntil: isActive ? paidUntil : 0,
            });
            
            console.log(`✅ Subscription ${isActive ? 'updated' : 'cancelled'} for ${user.email}`);
          } else {
            console.warn(`⚠️  Subscription event for unknown customer: ${customerId}`);
          }
          break;
        }
        
        case 'invoice.payment_failed': {
          const invoice = event.data.object;
          const customerId = invoice.customer;
          const user = await getUserByStripeCustomerId(customerId);
          
          if (user) {
            console.warn(`⚠️  Payment failed for ${user.email}`);
            // Optionally: Send email notification, update user status, etc.
          }
          break;
        }
        
        // 🔒 SetupIntent succeeded - Card verified for trial
        case 'setup_intent.succeeded': {
          const setupIntent = event.data.object;
          const userId = setupIntent.metadata?.userId;
          const email = setupIntent.metadata?.email;
          const purpose = setupIntent.metadata?.purpose;
          
          console.log(`💳 SetupIntent succeeded: userId=${userId}, email=${email}, purpose=${purpose}`);
          
          // Only process trial verification SetupIntents
          if (purpose === 'trial_verification' && userId) {
            const user = await getUserById(Number(userId));
            
            if (user && user.card_verified !== 1) {
              const now = Date.now();
              const freeUntilMs = now + 14 * 24 * 60 * 60 * 1000; // 14 days
              
              await updateUser(user.id, {
                cardVerified: 1,
                cardVerifiedAt: now,
                tier: "FREE14",
                freeStartAt: now,
                freeUntil: freeUntilMs,
              });
              
              console.log(`✅ [Webhook] Card verified for ${user.email} - FREE14 trial started`);
            } else if (!user) {
              console.warn(`⚠️  SetupIntent webhook: User not found for ID ${userId}`);
            } else {
              console.log(`ℹ️  SetupIntent webhook: User ${user.email} already verified`);
            }
          }
          break;
        }
        
        default:
          console.log(`ℹ️  Unhandled webhook event: ${event.type}`);
      }
      
      // Track commission for relevant events
      const commissionEvents = ["invoice.paid", "invoice.voided", "charge.refunded", "charge.dispute.created"];
      if (commissionEvents.includes(event.type)) {
        try {
          console.log(`\n💰 [Commission] Processing ${event.type}...`);
          await handleCommissionWebhook(event);
        } catch (commissionError) {
          console.error(`⚠️  Commission webhook error (${event.type}):`, commissionError.message);
          console.error(`   Stack:`, commissionError.stack);
          // Don't fail the main webhook - just log the error
        }
      }
      
      res.json({ received: true });
    } catch (err) {
      console.error(`❌ Webhook handler error: ${err.message}`);
      res.status(500).json({ error: 'Webhook handler failed' });
    }
  }
);

