function getUserTier(user) {
  if (!user) return "ANONYMOUS";
  if (user.tier) return String(user.tier).toUpperCase();
  return user.isPaid ? "PAID" : "FREE";
}

// ============================================================================
// Tier Limits Configuration (2026 Premium 5-Tier Pricing)
// ============================================================================
// VERIFIED = $4.95/month - Verified Access (starter tier)
// DAYTRADER = $35.99/month - Day Trader (active trading)
// SWING = $45.99/month - Swing Trader (position trading)
// PRO = $55.99/month - Pro Trader (professional use) - BEST SELLER
// ANNUAL = $350/year - Annual Plan (best value, same as PRO)
// ============================================================================
// Scanner limits optimized for Render 4GB RAM deployment
// Higher tiers get more scanner capacity for large watchlists
// ============================================================================
const TIER_LIMITS = {
  // New 5-Tier Premium Pricing (2026)
  VERIFIED: { maxScanner: 100, label: "Verified Access" },     // Starter: 100 symbols
  TRIAL: { maxScanner: 100, label: "Verified Access" },        // Alias for VERIFIED
  DAYTRADER: { maxScanner: 500, label: "Day Trader" },         // Active: 500 symbols
  SWING: { maxScanner: 750, label: "Swing Trader" },           // Position: 750 symbols
  PRO: { maxScanner: 1000, label: "Pro Trader" },              // Pro: 1000 symbols
  ANNUAL: { maxScanner: 1000, label: "Annual" },               // Annual: 1000 symbols
  PREMIUM: { maxScanner: 1000, label: "Premium" },             // Legacy: 1000 symbols
  // Legacy tiers (backward compatibility for existing users)
  FREE14: { maxScanner: 100, label: "Free Trial (Legacy)" },   // Legacy free trial
  TRIAL7: { maxScanner: 100, label: "7-Day Trial (Legacy)" },  // Legacy 7-day trial
  BASIC: { maxScanner: 500, label: "Basic (Legacy)" },         // Legacy basic tier
};

function getTierLimits(tier) {
  const t = String(tier || "TRIAL").toUpperCase();
  return TIER_LIMITS[t] || TIER_LIMITS.TRIAL;
}

// Helper: Clamp scanner limit based on user tier
function clampScannerLimit(requestedLimit, user) {
  if (!user) return Math.min(requestedLimit || 100, 100); // Anonymous users: max 100
  
  const access = computeAccessCountdown(user);
  const limits = getTierLimits(access.tier);
  const maxAllowed = limits.maxScanner;
  
  // Clamp requested limit to tier maximum
  const finalLimit = Math.min(requestedLimit || maxAllowed, maxAllowed);
  return Math.max(1, finalLimit); // Minimum 1
}

// ============================================================================
// Access Countdown Computation (New 2026 Clean Pricing)
// ============================================================================
/**
 * Compute user access mode and days remaining
 * Handles both camelCase and snake_case DB fields
 * Priority: PAID (PRO/ANNUAL) > TRIAL > LEGACY (FREE14) > EXPIRED
 * 
 * New Tiers:
 * - TRIAL: $4.95/month starter
 * - PRO: $55.99/month
 * - ANNUAL: $350/year
 */
function computeAccessCountdown(user) {
  const now = Date.now();

  const paidUntil = Number(user?.paid_until || user?.paidUntil || 0);
  const freeUntil = Number(user?.free_until || user?.freeUntil || 0);

  const calc = (untilMs) => {
    const msLeft = Math.max(0, untilMs - now);
    const totalHours = Math.ceil(msLeft / (60 * 60 * 1000));
    const days = Math.floor(totalHours / 24);
    const hours = totalHours % 24;
    return { msLeft, totalHours, days, hours };
  };

  const tierStr = String(user?.tier || "").toUpperCase();
  // Paid tiers: TRIAL ($4.95), PRO ($55.99), ANNUAL ($350), + legacy
  const looksPaidTier = ["TRIAL", "PRO", "ANNUAL", "PREMIUM", "BASIC", "TRIAL7"].includes(tierStr);
  const isPaidFlag = (user?.is_paid === 1 || user?.isPaid === true);
  
  // Priority 1: PAID subscription active
  if ((isPaidFlag || looksPaidTier) && paidUntil > now) {
    const t = calc(paidUntil);
    return {
      mode: "PAID",
      tier: tierStr || "PAID",
      until: paidUntil,
      ...t,
    };
  }

  // Priority 2: Legacy FREE14 (for existing users only)
  if (tierStr === "FREE14" && freeUntil > now) {
    const t = calc(freeUntil);
    return {
      mode: "FREE",
      tier: "FREE14",
      until: freeUntil,
      ...t,
    };
  }

  // EXPIRED - no active subscription
  return { mode: "EXPIRED", tier: tierStr || "NONE", until: 0, msLeft: 0, totalHours: 0, days: 0, hours: 0 };
}

// ============================================================================
// Auth Middleware (Real Authentication)
// ============================================================================
// Dev mode bypass (for local testing only)
const BYPASS_AUTH = String(process.env.BYPASS_AUTH || "false").toLowerCase() === "true";
if (BYPASS_AUTH) console.log("⚠️  BYPASS_AUTH=true - Authentication disabled for testing!");

function requireLogin(req, res, next) {
  // Allow bypass for local testing
  if (BYPASS_AUTH) return next();
  
  if (!req.isAuthenticated()) {
    // Check if it's an API request (JSON)
    const accept = String(req.headers.accept || "");
    if (accept.includes("application/json") || req.xhr) {
      return res.status(401).json({
        ok: false,
        error: "UNAUTHORIZED",
        message: "Please log in to access this feature.",
        action: "login",
        hint: "Start with a $4.95 trial month. Go annual for $350/year and get 1 month FREE.",
        loginUrl: "/auth/google?returnUrl=" + encodeURIComponent(req.originalUrl),
        pricingUrl: "/pricing"
      });
    }
    // Browser request - store original URL and redirect to pricing
    req.session.returnUrl = req.originalUrl;
    return res.redirect('/pricing?login_required=1');
  }
  next();
}

// ============================================================================
// Access Gate: Check if user has active subscription (TRIAL/PRO/ANNUAL)
// ============================================================================
function requireAccess(req, res, next) {
  // Allow bypass for local testing
  if (BYPASS_AUTH) return next();
  
  const u = req.user;
  const now = Date.now();

  // 🔑 ADMIN BYPASS: Admin users have full access without subscription
  const userEmail = String(u?.email || "").trim().toLowerCase();
  if (isAdminEmail(userEmail)) {
    return next();
  }

  // ✅ Check paid subscription: TRIAL ($4.95), PRO ($55.99), ANNUAL ($350), + legacy tiers
  const paidUntil = Number(u?.paid_until || u?.paidUntil || 0);
  const tierStr = String(u?.tier || "").toUpperCase();
  const looksPaidTier = ["TRIAL", "PRO", "ANNUAL", "PREMIUM", "BASIC", "TRIAL7"].includes(tierStr);
  const isPaidFlag = (u?.is_paid === 1 || u?.isPaid === true);
  const paidActive = (isPaidFlag || looksPaidTier) && (paidUntil > now);
  if (paidActive) return next();

  // Legacy FREE14 (for existing users only)
  const freeUntil = Number(u?.free_until || u?.freeUntil || 0);
  const freeActive = tierStr === "FREE14" && freeUntil > now;
  if (freeActive) return next();

  // 🔒 NEW_USER: User signed up but hasn't subscribed yet
  const tier = tierStr || "NONE";
  const isNewUser = tier === "PENDING_TRIAL" || tier === "NONE" || tier === "";
  if (isNewUser) {
    const accept = String(req.headers.accept || "");
    if (accept.includes("application/json") || req.xhr) {
      return res.status(403).json({
        ok: false,
        error: "SUBSCRIPTION_REQUIRED",
        message: "Please subscribe to access the scanner.",
        action: "subscribe",
        hint: "Start with a $4.95 trial month. Go annual for $350/year and get 1 month FREE.",
        pricingUrl: "/pricing",
        tier: tier
      });
    }
    return res.redirect("/pricing?subscribe=1");
  }

  // EXPIRED subscription
  const accept = String(req.headers.accept || "");
  if (accept.includes("application/json") || req.xhr) {
    const isLegacyTrial = tier === "FREE14" || tier === "TRIAL7";
    
    return res.status(403).json({
      ok: false,
      error: "EXPIRED",
      message: isLegacyTrial 
        ? "Your trial has expired. Subscribe to continue access." 
        : "Your subscription has expired. Please renew.",
      action: "renew",
      hint: "Resume access with Pro Monthly ($55.99/mo) or Annual ($350/year - 1 month FREE).",
      pricingUrl: "/pricing",
      tier: tier,
      expired: true
    });
  }
  return res.redirect("/pricing?expired=1");
}

// ============================================================================
// Admin Security Guards
// ============================================================================
function getClientIp(req) {
  const xff = (req.headers["x-forwarded-for"] || "").toString();
  return xff.split(",")[0].trim() || req.socket.remoteAddress || "";
}

function ipAllowed(req) {
  if (!ADMIN_IP_ALLOWLIST) return true; // allow all if not set
  const ip = getClientIp(req);
  const allow = ADMIN_IP_ALLOWLIST.split(",").map(s => s.trim()).filter(Boolean);
  return allow.includes(ip);
}

function keyAllowed(req) {
  if (!ADMIN_ACCESS_KEY) return true; // if not set, skip key check
  const key = String(req.query.key || req.headers["x-admin-key"] || "").trim();
  return key === ADMIN_ACCESS_KEY;
}

function adminGuard(req, res) {
  if (!ENABLE_ADMIN_LOGIN) { res.status(404).send("Not found"); return false; }
  if (!ipAllowed(req)) { res.status(403).send("Forbidden (IP)"); return false; }
  if (!keyAllowed(req)) { res.status(403).send("Forbidden (KEY)"); return false; }
  return true;
}

function requireAdmin(req, res, next) {
  // Check if user is logged in and has admin session flag
  if (!req.user || !req.session?.isAdmin) {
    // Also check if user's email is in admin list (fallback)
    const userEmail = String(req.user?.email || "").trim().toLowerCase();
    if (!isAdminEmail(userEmail)) {
      return res.status(403).send("Admin only");
    }
    // Grant admin session if email is in admin list
    req.session.isAdmin = true;
  }
  next();
}

