// ============================================================================
// Tier-Based Access Control
// ============================================================================
// Hierarchy: FREE14 < TRIAL7 < BASIC < PRO
// - FREE14: 14-day trial (🎁 ALL BOXES UNLOCKED!)
// - TRIAL7: $4.99 / 7 days (one-time payment)
// - BASIC: $20 / 40 days (subscription)
// - PRO: $35 / 40 days (subscription, all features)
const TIER_HIERARCHY = {
  FREE14: 0,   // 14-day free trial (🎁 FULL ACCESS to all boxes!)
  TRIAL7: 1,   // 7-day paid trial
  BASIC: 2,    // Basic subscription
  PRO: 3,      // Pro subscription (all features)
  PREMIUM: 4,  // Premium/Institutional
};

// WebSocket subscription limits by tier (symbols count)
const WS_SUB_LIMIT_BY_TIER = {
  FREE14: 200,
  TRIAL7: 200,
  BASIC: 200,
  PRO: 500,
  PREMIUM: 1000,
};

// Server-level WS tier (global connection, not per-user)
const WS_TIER_FOR_SERVER = String(process.env.WS_TIER_FOR_SERVER || "PREMIUM").toUpperCase();
const WS_SERVER_LIMIT = WS_SUB_LIMIT_BY_TIER[WS_TIER_FOR_SERVER] ?? 1000;

function getWsLimitForUser(user) {
  const tier = String(user?.tier || "BASIC").toUpperCase();
  return WS_SUB_LIMIT_BY_TIER[tier] ?? 200;
}

// Helper: dedupe symbols array
function uniqSymbols(arr) {
  return Array.from(new Set((arr || []).map(s => String(s || "").trim().toUpperCase()).filter(Boolean)));
}

// Build subscribe universe: IMPORTANT_SYMBOLS + optional extras
function buildSubscribeUniverseForUser(user, extraSymbols = []) {
  const base = parseSymbols(IMPORTANT_SYMBOLS || "");
  const extra = Array.isArray(extraSymbols) ? extraSymbols : [];
  return uniqSymbols([...extra, ...base]);
}

// Apply tier limit to symbols list
function applyTierLimit(symbols, limit) {
  return (symbols || []).slice(0, Math.max(20, Number(limit || 200)));
}

// Get server-level WS symbols (uses highest tier limit)
function getServerWsSymbols() {
  const syms = buildSubscribeUniverseForUser(null, []);
  return applyTierLimit(uniqSymbols(syms), WS_SERVER_LIMIT);
}

// FREE14 allowed boxes (by box ID)
// 🎁 UPDATED: FREE14 now has access to ALL BOXES for 14 days!
const FREE14_ALLOWED_BOXES = new Set([
  'gappers_dn',   // Top Gappers Down
  'gappers_up',   // Top Gappers Up
  'top_gainers',  // Top Gainers
  'top_losers',   // Top Losers
]);

function getUserTierLevel(user) {
  const tier = String(user?.tier || "FREE14").toUpperCase();
  return TIER_HIERARCHY[tier] ?? 0;
}

function hasTierAccess(user, requiredTier) {
  const userLevel = getUserTierLevel(user);
  const requiredLevel = TIER_HIERARCHY[String(requiredTier).toUpperCase()] ?? 0;
  return userLevel >= requiredLevel;
}

