// GET /dark-pool - All dark pool activity (top symbols by dark%)
// Now uses NQ100 (Nasdaq 100) as default base + movers for expanded coverage
app.get("/dark-pool", requireLogin, requireAccess, async (req, res) => {
  try {
    if (!ENABLE_DARK_POOL) {
      return res.status(400).json({ ok: false, error: "Dark pool tracking disabled" });
    }
    if (!POLYGON_API_KEY) {
      return res.status(400).json({ ok: false, error: "Polygon API key required for dark pool data" });
    }

    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const minDarkPct = Number(req.query.minDarkPct || 0);
    
    // Data source mode: "nq100_first" | "movers_only" | "combined"
    const sourceMode = String(req.query.source || DARK_POOL_SOURCE_MODE).toLowerCase();

    // Build ticker universe based on mode
    let tickers = [];
    
    if (sourceMode === "movers_only") {
      // Legacy behavior: movers only
      const g = await fetchMovers("gainers");
      const l = await fetchMovers("losers");
      const pool = [...(g.ok ? g.rows : []), ...(l.ok ? l.rows : [])]
        .map((x) => String(x?.ticker ?? x?.symbol ?? x?.sym ?? "").trim().toUpperCase())
        .filter(Boolean);
      tickers = Array.from(new Set(pool)).slice(0, 200);
    } else {
      // NQ100 first (default) or combined mode
      // Start with NQ100 tickers as base
      tickers = [...NQ100_TICKERS];
      
      // Then add movers for expanded coverage
      const g = await fetchMovers("gainers");
      const l = await fetchMovers("losers");
      const moverPool = [...(g.ok ? g.rows : []), ...(l.ok ? l.rows : [])]
        .map((x) => String(x?.ticker ?? x?.symbol ?? x?.sym ?? "").trim().toUpperCase())
        .filter(Boolean);
      
      // Add movers not already in NQ100
      const nq100Set = new Set(NQ100_TICKERS);
      for (const sym of moverPool) {
        if (!nq100Set.has(sym)) {
          tickers.push(sym);
        }
      }
      
      // Dedupe and limit
      tickers = Array.from(new Set(tickers)).slice(0, 300);
    }

    // Fetch dark pool data for all symbols
    const fetched = await mapPool(tickers, Math.min(4, SNAP_CONCURRENCY), async (sym) => {
      const x = await fetchDarkPoolData(sym);
      return { sym, ...x };
    });

    let results = fetched
      .filter((x) => x.ok && x.metrics)
      .map((x) => ({
        ...x.metrics,
        darkPoolScore: calculateDarkPoolScore({ ...x.metrics }),
      }))
      .filter((x) => (x.darkPoolPct ?? 0) >= minDarkPct);

    // Sort by dark pool %
    results.sort((a, b) => (b.darkPoolPct ?? 0) - (a.darkPoolPct ?? 0));
    results = results.slice(0, limit);

    res.json({
      ok: true,
      count: results.length,
      results,
      lookbackHours: DARK_POOL_LOOKBACK_HOURS,
      source: sourceMode,
      tickersScanned: tickers.length,
      nq100Count: NQ100_TICKERS.length,
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "dark-pool failed", detail: String(e?.message || e) });
  }
});

