// GET /dark-pool-alerts - Unusual dark pool activity
// Now uses NQ100 (Nasdaq 100) as default base + movers for expanded coverage
app.get("/dark-pool-alerts", requireLogin, async (req, res) => {
  try {
    if (!ENABLE_DARK_POOL) {
      return res.status(400).json({ ok: false, error: "Dark pool tracking disabled" });
    }
    if (!POLYGON_API_KEY) {
      return res.status(400).json({ ok: false, error: "Polygon API key required for dark pool data" });
    }

    // Check cache for alerts
    const cacheKey = "alerts";
    const hit = darkPoolAlertCache.get(cacheKey);
    if (hit && Date.now() - hit.ts < DARK_POOL_CACHE_TTL_MS) {
      return res.json(hit.data);
    }

    // Build ticker universe: NQ100 first + movers for expanded coverage
    let tickers = [...NQ100_TICKERS];
    
    const g = await fetchMovers("gainers");
    const l = await fetchMovers("losers");
    const moverPool = [...(g.ok ? g.rows : []), ...(l.ok ? l.rows : [])]
      .map((x) => String(x?.ticker ?? x?.symbol ?? x?.sym ?? "").trim().toUpperCase())
      .filter(Boolean);
    
    // Add movers not already in NQ100
    const nq100Set = new Set(NQ100_TICKERS);
    for (const sym of moverPool) {
      if (!nq100Set.has(sym)) {
        tickers.push(sym);
      }
    }
    
    // Dedupe and limit
    tickers = Array.from(new Set(tickers)).slice(0, 300);

    // Fetch dark pool data
    const fetched = await mapPool(tickers, Math.min(4, SNAP_CONCURRENCY), async (sym) => {
      const x = await fetchDarkPoolData(sym);
      return { sym, ...x };
    });

    const alerts = [];

    for (const item of fetched) {
      if (!item.ok || !item.metrics) continue;

      const m = item.metrics;
      const sym = m.symbol;

      // Alert 1: High dark pool %
      if ((m.darkPoolPct ?? 0) > 40) {
        alerts.push({
          symbol: sym,
          type: "HIGH_DARK_PCT",
          severity: "high",
          darkPoolPct: m.darkPoolPct,
          message: `${sym}: ${m.darkPoolPct}% dark pool activity (heavy institutional interest)`,
        });
      }

      // Alert 2: Large block trades
      if ((m.largestBlock ?? 0) > 1_000_000) {
        alerts.push({
          symbol: sym,
          type: "LARGE_BLOCK",
          severity: "medium",
          blockSize: m.largestBlock,
          blockCount: m.blockTrades,
          message: `${sym}: Large block trade ${Math.round(m.largestBlock / 1000)}K shares`,
        });
      }

      // Alert 3: Many block trades
      if ((m.blockTrades ?? 0) >= 10) {
        alerts.push({
          symbol: sym,
          type: "MULTIPLE_BLOCKS",
          severity: "medium",
          blockCount: m.blockTrades,
          avgBlockSize: m.avgBlockSize,
          message: `${sym}: ${m.blockTrades} block trades detected`,
        });
      }

      // Alert 4: High dark vs lit ratio
      if ((m.darkVsLitRatio ?? 0) > 1.5) {
        alerts.push({
          symbol: sym,
          type: "DARK_DOMINANCE",
          severity: "high",
          darkVsLitRatio: m.darkVsLitRatio,
          darkPoolPct: m.darkPoolPct,
          message: `${sym}: Dark volume ${m.darkVsLitRatio}x lit volume`,
        });
      }
    }

    // Sort by severity
    const severityOrder = { high: 0, medium: 1, low: 2 };
    alerts.sort((a, b) => (severityOrder[a.severity] ?? 2) - (severityOrder[b.severity] ?? 2));

    const payload = {
      ok: true,
      count: alerts.length,
      alerts: alerts.slice(0, 100),
      lookbackHours: DARK_POOL_LOOKBACK_HOURS,
      timestamp: Date.now(),
    };

    // Cache the result
    darkPoolAlertCache.set(cacheKey, { ts: Date.now(), data: payload });

    res.json(payload);
  } catch (e) {
    res.status(500).json({ ok: false, error: "dark-pool-alerts failed", detail: String(e?.message || e) });
  }
});

