// --------------------------------------------------------------------------
// 🌿 ECO MODE Helper - Reduces API calls by using aggressive caching
// --------------------------------------------------------------------------
function getEcoSettings(req) {
  const isEco = String(req.query.eco || req.query.cache || "").toLowerCase() === "1" || 
                String(req.query.eco || req.query.cache || "").toLowerCase() === "true" ||
                String(req.query.cache || "").toLowerCase() === "aggressive";
  
  return {
    enabled: isEco,
    // Eco mode: reduce concurrency to minimize simultaneous API calls
    concurrency: isEco ? Math.max(1, Math.floor(SNAP_CONCURRENCY / 2)) : SNAP_CONCURRENCY,
    // Eco mode: reduce enrichment limit to save API quota
    enrichLimit: isEco ? 50 : 200,
    // Eco mode: reduce aggregates limit
    aggsLimit: isEco ? Math.max(40, Math.floor(AGGS_5M_LIMIT / 2)) : AGGS_5M_LIMIT,
    // Eco mode: extend cache TTL significantly
    cacheTTL: isEco ? 120000 : 15000, // 2 minutes vs 15 seconds
  };
}

// --------------------------------------------------------------------------
// 🚀 TURBO MODE Helper - Detects turbo mode and adjusts performance settings
// --------------------------------------------------------------------------
function getTurboSettings(req) {
  const isTurbo = String(req.query.turbo || req.query.boost || "").toLowerCase() === "1" || 
                  String(req.query.turbo || req.query.boost || "").toLowerCase() === "true";
  
  return {
    enabled: isTurbo,
    concurrency: isTurbo ? Math.min(8, SNAP_CONCURRENCY * 2) : SNAP_CONCURRENCY,
    enrichLimit: isTurbo ? 300 : 200,
    aggsLimit: isTurbo ? 250 : AGGS_5M_LIMIT,
  };
}

// --------------------------------------------------------------------------
// 📈 OPTIONS FLOW MODE Helper - Detects options flow tracking mode
// --------------------------------------------------------------------------
function getOptionsFlowSettings(req) {
  const isOptionsFlow = String(req.query.optionsflow || req.query.trackcontracts || "").toLowerCase() === "1" || 
                        String(req.query.optionsflow || req.query.trackcontracts || "").toLowerCase() === "true";
  
  return {
    enabled: isOptionsFlow,
    // Options flow tracking is independent, doesn't affect other settings
  };
}

// --------------------------------------------------------------------------
// 🕵️ DARK POOL MODE Helper - Detects dark pool tracking mode
// --------------------------------------------------------------------------
function getDarkPoolSettings(req) {
  const isDarkPool = String(req.query.darkpool || req.query.trackblocks || "").toLowerCase() === "1" || 
                     String(req.query.darkpool || req.query.trackblocks || "").toLowerCase() === "true";
  
  return {
    enabled: isDarkPool && ENABLE_DARK_POOL,
    // Dark pool tracking doesn't affect concurrency
    // It's an additional enrichment step
  };
}

// --------------------------------------------------------------------------
// ⚡ COMBINED MODE Helper - Merges Options Flow, Dark Pool, Eco and Turbo settings
// --------------------------------------------------------------------------
function getCombinedSettings(req) {
  const optionsFlow = getOptionsFlowSettings(req);
  const darkPool = getDarkPoolSettings(req);
  const eco = getEcoSettings(req);
  const turbo = getTurboSettings(req);
  
  // If both eco and turbo modes are enabled, prioritize Eco to save resources
  if (eco.enabled && turbo.enabled) {
    return {
      enabled: true,
      mode: 'eco+turbo',
      // Eco wins for resource management
      concurrency: eco.concurrency,
      enrichLimit: Math.floor((eco.enrichLimit + turbo.enrichLimit) / 2),
      aggsLimit: Math.floor((eco.aggsLimit + turbo.aggsLimit) / 2),
      cacheTTL: eco.cacheTTL,
      ecoMode: true,
      turboMode: true,
      darkPoolMode: darkPool.enabled,
      optionsFlowMode: optionsFlow.enabled,
    };
  }
  
  if (eco.enabled) {
    return { 
      ...eco, 
      mode: 'eco', 
      ecoMode: true, 
      turboMode: false, 
      darkPoolMode: darkPool.enabled,
      optionsFlowMode: optionsFlow.enabled,
    };
  }
  
  if (turbo.enabled) {
    return { 
      ...turbo, 
      mode: 'turbo', 
      ecoMode: false, 
      turboMode: true, 
      darkPoolMode: darkPool.enabled,
      optionsFlowMode: optionsFlow.enabled,
    };
  }
  
  // Default mode
  return {
    enabled: false,
    mode: 'normal',
    concurrency: SNAP_CONCURRENCY,
    enrichLimit: 200,
    aggsLimit: AGGS_5M_LIMIT,
    cacheTTL: 15000,
    ecoMode: false,
    turboMode: false,
    darkPoolMode: darkPool.enabled,
    optionsFlowMode: optionsFlow.enabled,
  };
}

// --------------------------------------------------------------------------
// Helper function for scan operations
// --------------------------------------------------------------------------
async function runScanForSymbols(symbols, maxN, turboSettings = {}) {
  const concurrency = turboSettings.concurrency || SNAP_CONCURRENCY;
  const enrichLimit = turboSettings.enrichLimit || 200;
  
  const snaps = await mapPool(symbols, concurrency, async (t) => {
    const r = await fetchTickerSnapshot(t);
    return { ticker: t, ...r };
  });

  const good = snaps.filter((x) => x.ok);
  const bad = snaps.filter((x) => !x.ok);

  let rows = good.map((x) => normalizeSnapshotAuto(x.ticker, x.data)).map(addExtPctFromPrevClose);
  rows = await enrichRowsWithDailyOpen(rows, enrichLimit);
  rows = await enrichRowsWithFloat(rows, enrichLimit);

  const badRows = bad.map((x) => ({ symbol: x.ticker, source: "SNAPSHOT_FAILED" }));
  rows = rows.concat(badRows);

  const { rows: withInd, aggsErrors } = await attachIndicatorsIfEnabled(rows);
  rows = finalizeRows(withInd);

  rows.sort((a, b) => Math.abs(b.gapPct ?? 0) - Math.abs(a.gapPct ?? 0) || (b.volume ?? 0) - (a.volume ?? 0));
  return { rows, aggsErrors, turboUsed: turboSettings.enabled };
}

// --------------------------------------------------------------------------
// /scan — scan YOUR symbols list only (IMPORTANT_SYMBOLS or query symbols=)
// --------------------------------------------------------------------------
app.get("/scan", requireLogin, requireAccess, async (req, res) => {
  try {
    const miss = envMissingFor({ needAggs: ENABLE_5M_INDICATORS });
    if (miss.length) return res.status(400).json({ ok: false, error: "Missing env", miss });

    // ⚡ Check for combined eco + turbo mode
    const settings = getCombinedSettings(req);

    const q = req.query.symbols || req.query.symbol;
    let ALL;

    if (q) {
      ALL = parseSymbols(q);
    } else {
      // No query symbols => use per-user watchlist
      const wl = await getWatchlist(Number(req.user.id));
      ALL = wl.length ? wl : parseSymbols(IMPORTANT_SYMBOLS);
    }


    const MAX_FROM_UI = Number(req.query.max);
    const ENV_MAX = Number(process.env.SCAN_MAX_SYMBOLS || SCAN_MAX_SYMBOLS);
    const HARD_MAX = Number(process.env.SCAN_HARD_MAX || SCAN_HARD_MAX);

    const maxN = (() => {
      const base = Number.isFinite(MAX_FROM_UI) ? MAX_FROM_UI : ENV_MAX;
      return Math.max(20, Math.min(HARD_MAX, Math.floor(base)));
    })();

    const symbols = ALL.slice(0, maxN);

    // Use combined settings concurrency
    const snaps = await mapPool(symbols, settings.concurrency, async (t) => {
      const r = await fetchTickerSnapshot(t);
      return { ticker: t, ...r };
    });

    const good = snaps.filter((x) => x.ok);
    const bad = snaps.filter((x) => !x.ok);

    let rows = good.map((x) => normalizeSnapshotAuto(x.ticker, x.data)).map(addExtPctFromPrevClose);

    // ✅ Gap% overwrite (Polygon RTH open/prevClose) - use combined limit
    rows = await enrichRowsWithDailyOpen(rows, settings.enrichLimit);

    // ✅ Float enrich (FMP) - use combined limit
    rows = await enrichRowsWithFloat(rows, settings.enrichLimit);

    // ✅ Dark pool enrich (Polygon Trades API) - only if dark pool mode is enabled
    if (settings.darkPoolMode) {
      rows = await enrichRowsWithDarkPool(rows, settings.enrichLimit);
    }

    const badRows = bad.map((x) => ({
      symbol: x.ticker,
      price: null,
      open: null,
      prevClose: null,
      pricePct: null,
      gapPct: null,
      extPct: null,
      volume: null,
      floatShares: null,
      floatM: null,
      floatTurnoverPct: null,
      marketCapB: null,
      cap: null,
      demandScore: 0,
      signalIcon: "⚠️",
      paIcon: "",
      source: "SNAPSHOT_FAILED",
    }));

    rows = rows.concat(badRows);

    const { rows: withInd, aggsErrors } = await attachIndicatorsIfEnabled(rows);
    rows = finalizeRows(withInd);

    rows.sort(
      (a, b) =>
        Math.abs(b.gapPct ?? 0) - Math.abs(a.gapPct ?? 0) ||
        Math.abs(b.pricePct ?? 0) - Math.abs(a.pricePct ?? 0)
    );

    res.json({
      ok: true,
      mode: "symbols",
      scanned: symbols.length,
      results: rows,
      optionsFlowMode: settings.optionsFlowMode, // 📈 Indicate if options flow tracking was used
      darkPoolMode: settings.darkPoolMode, // 🕵️ Indicate if dark pool tracking was used
      ecoMode: settings.ecoMode, // 🌿 Indicate if eco was used
      turboMode: settings.turboMode, // 🚀 Indicate if turbo was used
      performanceMode: settings.mode, // ⚡ Combined mode indicator
      snapshotErrors: DEBUG
        ? bad.slice(0, 10).map((x) => ({
            ticker: x.ticker,
            status: x.status,
            url: x.url,
            errorDetail: x.errorDetail,
          }))
        : undefined,
      aggsErrors: DEBUG ? aggsErrors.slice(0, 10) : undefined,
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "Scan failed", detail: String(e?.message || e) });
  }
});

