// --------------------------------------------------------------------------
// Price% Movers by Price Range ($2-$20, $5-$55, etc.)
// --------------------------------------------------------------------------
app.get("/price-move-range", requireLogin, requireAccess, async (req, res) => {
  try {
    const minPrice = n(req.query.minPrice);
    const maxPrice = n(req.query.maxPrice);
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 120), 10, 300);

    // Build a solid universe first
    const base = await buildRowsFromMoversUnion({ cap, limit: Math.max(250, limit * 6), sortMode: "active" });
    if (!base.ok) return res.status(base.status).json(base.body);

    let rows = Array.isArray(base.body?.results) ? base.body.results : [];

    // Filter price range
    rows = rows.filter(r => pricePass(r, minPrice, maxPrice));

    // Sort by Price (ascending: low → high)
    rows.sort((a, b) => (n(a.price) ?? 1e18) - (n(b.price) ?? 1e18));

    rows = rows.slice(0, limit);

    return res.json({
      ok: true,
      box: "price-move-range",
      minPrice,
      maxPrice,
      cap,
      count: rows.length,
      results: rows
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "price-move-range failed", detail: String(e?.message || e) });
  }
});

// ==============================
// 🔥 VWAP Break Auto-Add Box
// ==============================
const VWAP_BOX_ID = "vwap_break_box";

// thresholds (day trader default — bạn có thể chỉnh)
const VWAP_BREAK_MIN_GAP = 5;       // Gap% >= 5
const VWAP_BREAK_MIN_SCORE = 70;    // Score >= 70
const VWAP_BREAK_MIN_ROVL = 1.5;    // volRatio_5m >= 1.5 (momentum)
const VWAP_BREAK_MAX_KEEP = 80;     // giữ tối đa 80 ticker
const VWAP_BREAK_TTL_MS = 45 * 60 * 1000; // 45 phút tự expire

const vwapSeen = new Set();            // đã từng vào box
const vwapPinned = new Map();          // sym -> row with _pinnedAt

function vwapCandidate(row){
  const gap = Number(row?.gapPct);
  const score = Number(row?.score);
  const rovl = Number(row?.volRatio_5m);

  // "strong break VWAP" = aboveVWAP_5m true + volSpike_5m true (bạn đã có)
  const above = Boolean(row?.aboveVWAP_5m);
  const spike = Boolean(row?.volSpike_5m);

  if (!above) return false;

  // mạnh hơn: phải có spike OR rovl lớn
  if (!(spike || (Number.isFinite(rovl) && rovl >= VWAP_BREAK_MIN_ROVL))) return false;

  // gap + score
  if (!Number.isFinite(gap) || Math.abs(gap) < VWAP_BREAK_MIN_GAP) return false;
  if (!Number.isFinite(score) || score < VWAP_BREAK_MIN_SCORE) return false;

  return true;
}

function pruneVWAP(){
  const now = Date.now();

  // TTL cleanup
  for (const [sym, r] of vwapPinned.entries()){
    const ts = Number(r?._pinnedAt || 0);
    if (ts && (now - ts) > VWAP_BREAK_TTL_MS) vwapPinned.delete(sym);
  }

  // size cap
  if (vwapPinned.size > VWAP_BREAK_MAX_KEEP){
    const arr = Array.from(vwapPinned.entries()).sort((a,b)=> (a[1]?._pinnedAt||0) - (b[1]?._pinnedAt||0));
    const drop = arr.length - VWAP_BREAK_MAX_KEEP;
    for (let i=0;i<drop;i++) vwapPinned.delete(arr[i][0]);
  }
}

// Rank: Gap% -> Momentum (score/rovl/floatTurn/vol)
function rankGapMomentum(rows){
  const n = (v)=> (Number.isFinite(Number(v)) ? Number(v) : 0);
  return [...rows].sort((a,b)=>{
    const g = Math.abs(n(b.gapPct)) - Math.abs(n(a.gapPct));
    const momA = n(a.score) || n(a.volRatio_5m) || n(a.floatTurnoverPct) || n(a.volume);
    const momB = n(b.score) || n(b.volRatio_5m) || n(b.floatTurnoverPct) || n(b.volume);
    return g || (momB - momA);
  });
}

function addToVWAPBox(row, sourceBoxId){
  const sym = String(row?.symbol || "").trim().toUpperCase();
  if (!sym) return;

  // update existing pinned row
  if (vwapPinned.has(sym)){
    const old = vwapPinned.get(sym) || {};
    vwapPinned.set(sym, { ...old, ...row, _pinnedAt: old._pinnedAt || Date.now(), _from: sourceBoxId || old._from || "" });
    return;
  }

  // new candidate
  vwapSeen.add(sym);
  vwapPinned.set(sym, { ...row, _pinnedAt: Date.now(), _from: sourceBoxId || "" });

  pruneVWAP();

  // 🔔 optional bell
  // ringBell();
}

// =======================================================
// ✅ Gap Rank by Price Range
// GET /box/gap-rank-price?minPrice=3&maxPrice=30&limit=220&minGap=0&abs=true
// Rank: abs(gapPct) desc
// =======================================================
app.get("/box/gap-rank-price", requireLogin, requireAccess, async (req, res) => {
  try {
    const minPrice = Number(req.query.minPrice ?? 3);
    const maxPrice = Number(req.query.maxPrice ?? 30);
    const limit = clamp(Number(req.query.limit || 220), 10, 500);

    // optional: minimum gap filter
    const minGap = Number(req.query.minGap ?? 0);
    const abs = String(req.query.abs ?? "true").toLowerCase() === "true";

    // Build gappers universe using your existing /list logic (gainers+losers union)
    // Instead of calling HTTP /list again, we reuse the same internal flow:
    const g = await fetchMovers("gainers");
    const l = await fetchMovers("losers");
    if (!g.ok && !l.ok) {
      return res.status(500).json({ ok:false, error:"Movers failed", moverDebug:{ g, l } });
    }

    const pool = [...(g.ok ? g.rows : []), ...(l.ok ? l.rows : [])]
      .map((x) => String(x?.ticker ?? x?.symbol ?? x?.sym ?? "").trim().toUpperCase())
      .filter(Boolean);

    const tickers = Array.from(new Set(pool)).slice(0, 1200);

    const snaps = await mapPool(tickers, SNAP_CONCURRENCY, async (t) => {
      const r = await fetchTickerSnapshot(t);
      return { ticker: t, ...r };
    });

    const good = snaps.filter((x) => x.ok);
    let rows = good.map((x) => normalizeSnapshotAuto(x.ticker, x.data)).map(addExtPctFromPrevClose);

    // ✅ Overwrite gap with Polygon RTH open/prevClose
    rows = await enrichRowsWithDailyOpen(rows, 300);

    // ✅ Float enrich (optional)
    rows = await enrichRowsWithFloat(rows, 300);

    // ✅ Indicators + score + signal + PA
    const { rows: withInd } = await attachIndicatorsIfEnabled(rows);
    rows = finalizeRows(withInd);

    // ✅ Price range filter $3-$30
    rows = rows.filter(r => {
      const p = Number(r?.price);
      return Number.isFinite(p) && p >= minPrice && p <= maxPrice;
    });

    // ✅ Gap filter optional
    if (Number.isFinite(minGap) && minGap > 0) {
      rows = rows.filter(r => {
        const g0 = Number(r?.gapPct);
        if (!Number.isFinite(g0)) return false;
        return abs ? Math.abs(g0) >= minGap : g0 >= minGap;
      });
    }

    // ✅ Rank: abs(gapPct) desc
    rows.sort((a,b) => Math.abs(Number(b?.gapPct) || 0) - Math.abs(Number(a?.gapPct) || 0));

    rows = rows.slice(0, limit);

    return res.json({
      ok:true,
      box:"gap_rank_price",
      priceRange: { minPrice, maxPrice },
      minGap: minGap || 0,
      abs,
      count: rows.length,
      results: rows
    });

  } catch (e) {
    return res.status(500).json({ ok:false, error:"box/gap-rank-price failed", detail:String(e?.message||e) });
  }
});

// =======================================================
// 🎯 VWAP Follow Trading System
// GET /box/vwap-follow?strategy=filter&direction=long&cap=small&limit=100
// Strategies: filter | entry | exit | combined
// =======================================================
app.get("/box/vwap-follow", requireLogin, requireAccess, async (req, res) => {
  try {
    const strategy = String(req.query.strategy || "filter").toLowerCase();
    const direction = String(req.query.direction || "long").toLowerCase();
    const cap = String(req.query.cap || "small").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const minConfidence = Number(req.query.minConfidence || 0.3); // Lowered for more sensitivity
    const bufferPct = Number(req.query.bufferPct || 0);

    // Build universe from movers
    console.log(`[VWAP-FOLLOW] Starting scan: strategy=${strategy}, direction=${direction}, cap=${cap}`);
    
    const g = await fetchMovers("gainers");
    const l = await fetchMovers("losers");
    
    console.log(`[VWAP-FOLLOW] Movers fetched: gainers=${g.ok}/${g.rows?.length || 0}, losers=${l.ok}/${l.rows?.length || 0}`);
    
    // Combine gainers and losers
    const pool = [...(g.ok ? g.rows : []), ...(l.ok ? l.rows : [])]
      .map((x) => String(x?.ticker ?? x?.symbol ?? x?.sym ?? "").trim().toUpperCase())
      .filter(Boolean);

    const tickers = Array.from(new Set(pool)).slice(0, 800);
    
    if (tickers.length === 0) {
      console.log(`[VWAP-FOLLOW] No tickers from movers`);
      return res.json({
        ok: true,
        box: "vwap_follow",
        strategy,
        direction,
        cap,
        minConfidence,
        count: 0,
        totalScanned: 0,
        withVwap: 0,
        results: [],
        note: "No movers data available (market may be closed)"
      });
    }
    
    console.log(`[VWAP-FOLLOW] Fetching snapshots for ${tickers.length} tickers...`);

    // Fetch snapshots in parallel
    const snaps = await mapPool(tickers, SNAP_CONCURRENCY, async (t) => {
      const r = await fetchTickerSnapshot(t);
      return { ticker: t, ...r };
    });

    const good = snaps.filter((x) => x.ok);
    console.log(`[VWAP-FOLLOW] Got ${good.length} valid snapshots`);
    
    let rows = good.map((x) => normalizeSnapshotAuto(x.ticker, x.data)).map(addExtPctFromPrevClose);

    // Cap filter (cap="all" keeps everything)
    if (cap !== "all") {
      rows = rows.filter(r => capPass(r, cap));
      console.log(`[VWAP-FOLLOW] After cap filter (${cap}): ${rows.length} rows`);
    }

    // Enrich with RTH gap
    rows = await enrichRowsWithDailyOpen(rows, 300);

    // Enrich with float
    if (ENABLE_FLOAT_ENRICH && FMP_API_KEY) {
      rows = await enrichRowsWithFloat(rows, 300);
    }

    // ✅ MUST attach indicators (includes VWAP)
    if (!ENABLE_5M_INDICATORS) {
      return res.status(500).json({ 
        ok: false, 
        error: "VWAP Follow requires 5M indicators. Set ENABLE_5M_INDICATORS=true in .env" 
      });
    }

    // 🔧 For ENTRY strategy, we need the raw 5m bars for pattern detection
    const needBars = strategy === "entry" || strategy === "combined";
    const { rows: withInd } = await attachIndicatorsIfEnabled(rows, needBars);
    rows = finalizeRows(withInd);

    // 🔧 FALLBACK: If vwap_5m missing, use prevClose as VWAP proxy
    rows = rows.map(r => {
      if (!r.vwap_5m && r.prevClose) {
        r.vwap_5m = r.prevClose; // Use prevClose as VWAP proxy
        r.vwapFallback = true;
      }
      return r;
    });

    console.log(`[VWAP-FOLLOW] Rows with VWAP: ${rows.filter(r => r.vwap_5m).length}/${rows.length}`);

    // Apply VWAP Follow scan
    const vwapResults = vwapFollowScan(rows, {
      strategy,
      direction,
      minConfidence,
      bufferPct
    });

    console.log(`[VWAP-FOLLOW] Results after scan: ${vwapResults.length} (strategy=${strategy}, direction=${direction})`);

    // Sort by gap + momentum
    const num = (v) => (Number.isFinite(Number(v)) ? Number(v) : 0);
    vwapResults.sort((a, b) => {
      const g = Math.abs(num(b?.gapPct)) - Math.abs(num(a?.gapPct));
      const momA = num(a?.score) || num(a?.volRatio_5m) || num(a?.floatTurnoverPct) || num(a?.volume);
      const momB = num(b?.score) || num(b?.volRatio_5m) || num(b?.floatTurnoverPct) || num(b?.volume);
      return g || (momB - momA);
    });

    // Clean up results - remove _bars5m from output (too large)
    const final = vwapResults.slice(0, limit).map(r => {
      const { _bars5m, ...rest } = r;
      return rest;
    });

    return res.json({
      ok: true,
      box: "vwap_follow",
      strategy,
      direction,
      cap,
      minConfidence,
      count: final.length,
      totalScanned: rows.length,
      withVwap: rows.filter(r => r.vwap_5m).length,
      results: final
    });

  } catch (e) {
    return res.status(500).json({ ok: false, error: "box/vwap-follow failed", detail: String(e?.message || e) });
  }
});

// --------------------------------------------------------------------------
// Options Flow - Unusual Options Activity
// Supports custom symbols via ?symbols= or uses NQ100 + Scanner data
// Uses shared NQ100_TICKERS defined at top of file (line ~254)
// --------------------------------------------------------------------------

// Shared handler function for both /options-flow and /option-flow
const handleOptionsFlow = async (req, res) => {
  try {
    const limit = clamp(Number(req.query.limit || 100), 10, 300);
    const customSymbols = req.query.symbols ? String(req.query.symbols).toUpperCase().split(",").map(s => s.trim()).filter(Boolean) : [];
    const useNQ100 = String(req.query.nq100 || "true").toLowerCase() === "true";
    const useScanner = String(req.query.scanner || "true").toLowerCase() === "true";
    
    // Build symbol list: Custom + NQ100 + Scanner movers
    let symbolsToScan = new Set(customSymbols);
    
    // Add NQ100 tickers
    if (useNQ100) {
      NQ100_TICKERS.forEach(s => symbolsToScan.add(s));
    }
    
    // Add active movers from scanner
    let scannerStocks = [];
    if (useScanner) {
      const moversResponse = await buildRowsFromMoversUnion({ cap: "all", limit: 50, sortMode: "active" });
      if (moversResponse.ok && moversResponse.body.results) {
        scannerStocks = moversResponse.body.results;
        scannerStocks.forEach(s => symbolsToScan.add(s.symbol));
      }
    }
    
    const allSymbols = Array.from(symbolsToScan).slice(0, 150); // Cap at 150 symbols
    
    if (allSymbols.length === 0) {
      return res.json({ ok: true, results: [], note: "No symbols to scan" });
    }
    
    // Fetch real-time data for symbols via snapshot
    let stocks = [];
    
    // First, use scanner stocks if available (they already have data)
    if (scannerStocks.length > 0) {
      stocks = [...scannerStocks];
    }
    
    // Add NQ100 tickers by fetching snapshots in batches
    const symbolsNeedingData = allSymbols.filter(s => !stocks.find(st => st.symbol === s));
    
    if (symbolsNeedingData.length > 0) {
      // Fetch snapshots in parallel with concurrency limit
      const batchSize = 10;
      for (let i = 0; i < Math.min(symbolsNeedingData.length, 50); i += batchSize) {
        const batch = symbolsNeedingData.slice(i, i + batchSize);
        const snapPromises = batch.map(async (sym) => {
          try {
            const snap = await fetchTickerSnapshot(sym);
            if (snap.ok && snap.data) {
              return normalizeSnapshotAuto(sym, snap.data);
            }
          } catch (e) {
            // Ignore individual failures
          }
          return null;
        });
        const snapResults = await Promise.all(snapPromises);
        snapResults.filter(Boolean).forEach(r => stocks.push(r));
      }
    }
    
    // If still no stocks, use movers fallback
    if (stocks.length === 0) {
      const fallbackResponse = await buildRowsFromMoversUnion({ cap: "all", limit: 100, sortMode: "active" });
      if (fallbackResponse.ok) {
        stocks = fallbackResponse.body.results || [];
      }
    }
    
    // Generate options flow based on stock activity
    // Creates BOTH CALL and PUT for each ticker
    const optionsData = [];
    const now = Date.now();
    
    console.log(`[options-flow] Processing ${stocks.length} stocks`);
    if (stocks.length > 0) {
      console.log(`[options-flow] Sample stock[0]:`, JSON.stringify(stocks[0]).substring(0, 200));
    }
    let skippedNoPrice = 0;
    let skippedLowPremium = 0;
    
    for (const stock of stocks) {
      const sym = stock.symbol;
      // Use prevClose as fallback when price is 0 (market closed)
      let price = n(stock.price) || 0;
      if (price <= 0) {
        price = n(stock.prevClose) || 0;
      }
      const pricePct = n(stock.pricePct) || 0;
      // Use minimum volume for contract calculation when volume is 0
      const volume = Math.max(n(stock.volume) || 0, 100000); // Min 100K volume
      const gapPct = n(stock.gapPct) || 0;
      const floatTurn = n(stock.floatTurnoverPct) || 0;
      
      // Skip if still no price available
      if (price <= 0) {
        skippedNoPrice++;
        continue;
      }
      
      // Base activity metrics
      const activityScore = Math.abs(pricePct) + Math.abs(gapPct) * 0.5 + floatTurn * 0.1;
      const baseImpliedVol = 0.25 + activityScore * 0.03;
      
      // Calculate strike rounding based on price
      // For penny stocks (< $1), use 0.5 strike rounding to avoid strike=0
      let strikeRound;
      if (price < 1) {
        strikeRound = 0.5;  // Penny stocks: 0.5, 1.0, 1.5, etc
      } else if (price < 5) {
        strikeRound = 0.5;  // Low price: 0.5 increments
      } else if (price < 20) {
        strikeRound = 1;    // $1 increments
      } else if (price < 100) {
        strikeRound = 5;    // $5 increments
      } else {
        strikeRound = 10;   // $10 increments
      }
      
      // Generate multiple expirations
      const expirations = [
        { days: 7, label: "weekly" },
        { days: 14, label: "2week" },
        { days: 30, label: "monthly" },
      ];
      
      // Create BOTH CALL and PUT for each ticker
      for (const contractType of ["CALL", "PUT"]) {
        const isCall = contractType === "CALL";
        
        // Determine sentiment based on stock movement + contract type
        const isBullishMove = pricePct > 0 || gapPct > 1;
        let sentiment, flowType;
        
        if (isCall) {
          sentiment = isBullishMove ? "🟢 BULLISH" : "🟡 NEUTRAL";
          flowType = isBullishMove ? "BUY" : "SELL";
        } else {
          sentiment = isBullishMove ? "🟡 HEDGE" : "🔴 BEARISH";
          flowType = isBullishMove ? "HEDGE" : "BUY";
        }
        
        // Calculate strike (slightly OTM)
        const strikeOffset = isCall ? 1.03 : 0.97;
        let strike = price * strikeOffset;
        // Round to nearest strike increment
        strike = round2(Math.max(strikeRound, Math.round(strike / strikeRound) * strikeRound));
        
        // Pick a random expiration
        const expInfo = expirations[Math.floor(Math.random() * expirations.length)];
        const daysToExp = expInfo.days + Math.floor(Math.random() * 7);
        const expDate = new Date(now + daysToExp * 86400000);
        const expiration = expDate.toISOString().split('T')[0];
        
        // Calculate option price (calls typically worth more when bullish, puts when bearish)
        const ivAdjust = isCall ? (isBullishMove ? 1.1 : 0.9) : (isBullishMove ? 0.9 : 1.1);
        const impliedVol = baseImpliedVol * ivAdjust;
        const moneyness = isCall ? Math.max(0, price - strike) : Math.max(0, strike - price);
        const intrinsicValue = moneyness;
        const timeValue = price * impliedVol * Math.sqrt(daysToExp / 365) * 0.35;
        const optionPrice = round2(Math.max(0.05, intrinsicValue + timeValue));
        
        // Volume based on activity and flow direction
        const volumeMultiplier = (flowType === "BUY" || flowType === "HEDGE") ? 1.2 : 0.8;
        const contractVolume = Math.round(Math.max(100, (volume / 20000) * volumeMultiplier * (0.8 + Math.random() * 0.4)));
        const openInterest = Math.round(contractVolume * (2 + Math.random() * 3));
        const volumeOIRatio = openInterest > 0 ? round2(contractVolume / openInterest) : 0;
        const premium = Math.round(contractVolume * optionPrice * 100);
        
        // Skip very small premium (lowered threshold to show more options)
        if (premium < 1000) {
          skippedLowPremium++;
          continue;
        }
        
        // Delta calculation
        const baseDelta = isCall ? 0.50 : -0.50;
        const deltaAdjust = (price - strike) / price * 0.3;
        const delta = round2(Math.max(-0.95, Math.min(0.95, baseDelta + (isCall ? deltaAdjust : -deltaAdjust))));
        
        optionsData.push({
          symbol: sym,
          contractSymbol: `${sym}${expiration.replace(/-/g, '')}${contractType[0]}${strike}`,
          contractType: contractType,
          strike: strike,
          expiration: expiration,
          expirationLabel: expInfo.label,
          volume: contractVolume,
          openInterest: openInterest,
          volumeOIRatio: volumeOIRatio,
          price: optionPrice,
          premium: premium,
          premiumM: round2(premium / 1_000_000),
          premiumK: round2(premium / 1_000),
          bid: round2(optionPrice * 0.95),
          ask: round2(optionPrice * 1.05),
          spread: round2(optionPrice * 0.10),
          sentiment: sentiment,
          flowType: flowType,
          delta: delta,
          gamma: round2(0.02 + Math.random() * 0.03),
          theta: round2(-0.02 - Math.random() * 0.03),
          vega: round2(0.06 + Math.random() * 0.06),
          impliedVolatility: round2(impliedVol * 100),
          daysToExpiration: daysToExp,
          // Stock data for reference
          stockPrice: round2(price),
          stockChange: round2(pricePct),
          stockGap: round2(gapPct),
          stockVolume: volume,
          floatTurnover: round2(floatTurn),
          // For table display
          pricePct: round2(pricePct),
          gapPct: round2(gapPct),
        });
      }
    }
    
    // MOBILE APP FORMAT: Aggregate by symbol and return stocks with option flow metrics
    const stocksWithOptions = new Map();
    
    for (const opt of optionsData) {
      const sym = opt.symbol;
      if (!stocksWithOptions.has(sym)) {
        // Find the original stock data
        const stockData = stocks.find(s => s.symbol === sym) || {};
        stocksWithOptions.set(sym, {
          symbol: sym,
          price: opt.stockPrice,
          pricePct: opt.stockChange,
          gapPct: opt.stockGap,
          volume: opt.stockVolume,
          floatTurnoverPct: opt.floatTurnover,
          prevClose: stockData.prevClose,
          floatM: stockData.floatM,
          marketCapB: stockData.marketCapB,
          cap: stockData.cap,
          // Option flow aggregates
          optionVolume: 0,
          optionOI: 0,
          optionPremium: 0,
          optionSentiment: null,
          _contracts: 0,
          _bullishCount: 0,
          _bearishCount: 0,
        });
      }
      
      const stock = stocksWithOptions.get(sym);
      stock.optionVolume += opt.volume;
      stock.optionOI += opt.openInterest;
      stock.optionPremium += opt.premium;
      stock._contracts++;
      
      // Count sentiment
      if (opt.sentiment.includes('BULLISH')) stock._bullishCount++;
      if (opt.sentiment.includes('BEARISH')) stock._bearishCount++;
    }
    
    // Determine overall sentiment for each stock
    const results = Array.from(stocksWithOptions.values()).map(stock => {
      if (stock._bullishCount > stock._bearishCount) {
        stock.optionSentiment = 'BULLISH';
      } else if (stock._bearishCount > stock._bullishCount) {
        stock.optionSentiment = 'BEARISH';
      } else {
        stock.optionSentiment = 'NEUTRAL';
      }
      // Remove internal counters
      delete stock._contracts;
      delete stock._bullishCount;
      delete stock._bearishCount;
      return stock;
    });
    
    // Sort by option premium (highest first)
    results.sort((a, b) => (b.optionPremium || 0) - (a.optionPremium || 0));
    
    console.log(`[options-flow] Aggregated ${results.length} stocks with options data. Total contracts: ${optionsData.length}`);
    
    res.json({
      ok: true,
      mode: "options_flow",
      symbolsRequested: allSymbols.length,
      symbolsScanned: stocks.length,
      totalContracts: optionsData.length,
      results: results.slice(0, limit),
      note: "📊 Options flow from NQ100 + Scanner. Aggregated by symbol.",
      disclaimer: "⚠️ EDUCATIONAL PURPOSE: This options flow data is simulated from stock market activity for learning and analysis. Not real-time options order flow from exchanges. Use for pattern recognition and strategy education only.",
    });
  } catch (e) {
    console.error("[options-flow] Error:", e);
    res.status(500).json({ ok: false, error: "options-flow failed", detail: String(e?.message || e) });
  }
};

// Main endpoint (no auth required for mobile app)
app.get("/options-flow", handleOptionsFlow);

// ALIAS: /option-flow (singular) for iOS app compatibility
app.get("/option-flow", handleOptionsFlow);

// --------------------------------------------------------------------------
// Single Symbol Option Flow API (for trading page)
// --------------------------------------------------------------------------
app.get("/api/options/flow/:symbol", async (req, res) => {
  try {
    const symbol = String(req.params.symbol || "").trim().toUpperCase();
    const limit = clamp(Number(req.query.limit || 40), 5, 100);
    
    if (!symbol) {
      return res.status(400).json({ ok: false, error: "Symbol required" });
    }
    
    // Fetch real-time stock data
    const snap = await fetchTickerSnapshot(symbol);
    if (!snap.ok || !snap.data) {
      return res.json({ ok: false, error: "Failed to fetch stock data" });
    }
    
    const stock = normalizeSnapshotAuto(symbol, snap.data);
    // Use prevClose as fallback when price is 0 (market closed)
    let price = n(stock.price) || 0;
    if (price <= 0) {
      price = n(stock.prevClose) || 0;
    }
    const pricePct = n(stock.pricePct) || 0;
    // Use minimum volume when volume is 0
    const volume = Math.max(n(stock.volume) || 0, 100000);
    const gapPct = n(stock.gapPct) || 0;
    const floatTurn = n(stock.floatTurnoverPct) || 0;
    
    if (price <= 0) {
      return res.json({ ok: false, error: "Invalid stock price" });
    }
    
    // Generate options flow
    const optionsData = [];
    const now = Date.now();
    const activityScore = Math.abs(pricePct) + Math.abs(gapPct) * 0.5 + floatTurn * 0.1;
    const baseImpliedVol = 0.25 + activityScore * 0.03;
    
    // Calculate strike rounding based on price
    // For penny stocks (< $1), use 0.5 strike rounding to avoid strike=0
    let strikeRound;
    if (price < 1) {
      strikeRound = 0.5;  // Penny stocks: 0.5, 1.0, 1.5, etc
    } else if (price < 5) {
      strikeRound = 0.5;  // Low price: 0.5 increments
    } else if (price < 20) {
      strikeRound = 1;    // $1 increments
    } else if (price < 100) {
      strikeRound = 5;    // $5 increments
    } else {
      strikeRound = 10;   // $10 increments
    }
    
    // Generate expirations - 4 weeks
    const expirations = [
      { days: 7, label: "1W" },
      { days: 14, label: "2W" },
      { days: 21, label: "3W" },
      { days: 28, label: "4W" },
    ];
    
    // Generate ALL combinations: strikes × expirations × (CALL + PUT)
    // This creates a comprehensive options chain
    const isBullishMove = pricePct > 0 || gapPct > 1;
    
    // Generate 5 different strikes: 2 ITM, ATM, 2 OTM for each type
    const callMultipliers = [0.95, 0.97, 1.00, 1.03, 1.05];
    const putMultipliers = [0.95, 0.97, 1.00, 1.03, 1.05];
    const allMultipliers = [...new Set([...callMultipliers, ...putMultipliers])]; // Remove duplicates
    
    for (const contractType of ["CALL", "PUT"]) {
      const isCall = contractType === "CALL";
      const strikeMultipliers = isCall ? callMultipliers : putMultipliers;
      
      for (const mult of strikeMultipliers) {
        for (const expInfo of expirations) {
          // Sentiment based on stock movement and contract type
          let sentiment, flowType;
          if (isCall) {
            sentiment = isBullishMove ? "🟢 BULLISH" : "🟡 NEUTRAL";
            flowType = isBullishMove ? "BUY" : "SELL";
          } else {
            sentiment = isBullishMove ? "🟡 HEDGE" : "🔴 BEARISH";
            flowType = isBullishMove ? "HEDGE" : "BUY";
          }
          
          // Calculate strike
          let strike = price * mult;
          // Round to nearest strike increment, ensure minimum = strikeRound
          strike = round2(Math.max(strikeRound, Math.round(strike / strikeRound) * strikeRound));
          
          // Calculate expiration
          const daysToExp = expInfo.days + Math.floor(Math.random() * 3);
          const expDate = new Date(now + daysToExp * 86400000);
          const expiration = expDate.toISOString().split('T')[0];
          const expDateDisplay = `${String(expDate.getMonth() + 1).padStart(2, '0')}/${String(expDate.getDate()).padStart(2, '0')}`;
          
          // Calculate option price
          const ivAdjust = isCall ? (isBullishMove ? 1.1 : 0.9) : (isBullishMove ? 0.9 : 1.1);
          const impliedVol = baseImpliedVol * ivAdjust;
          const moneyness = isCall ? Math.max(0, price - strike) : Math.max(0, strike - price);
          const intrinsicValue = moneyness;
          const timeValue = price * impliedVol * Math.sqrt(daysToExp / 365) * 0.35;
          const optionPrice = round2(Math.max(0.05, intrinsicValue + timeValue));
          
          // Volume calculation
          const volumeMultiplier = (flowType === "BUY" || flowType === "HEDGE") ? 1.2 : 0.8;
          const contractVolume = Math.round(Math.max(100, (volume / 20000) * volumeMultiplier * (0.8 + Math.random() * 0.4)));
          const premium = Math.round(contractVolume * optionPrice * 100);
          
          // Skip very small premium (lowered threshold to show more options)
          if (premium < 500) continue;
          
          // ITM/OTM
          const isITM = (isCall && strike < price) || (!isCall && strike > price);
          
          // Time ago (simulate real-time)
          const minutesAgo = Math.floor(Math.random() * 45) + 1;
          const timeAgo = minutesAgo < 60 ? `${minutesAgo}m ago` : `${Math.floor(minutesAgo / 60)}h ago`;
          
          optionsData.push({
            name: `${symbol} ${expDateDisplay} $${strike} ${contractType}`,
            contractSymbol: `${symbol}${expiration.replace(/-/g, '')}${contractType[0]}${strike}`,
            type: contractType,
            strike: strike,
            expDate: expDateDisplay,
            expiration: expiration,
            expirationLabel: expInfo.label,
            premium: round2(optionPrice),
            premiumTotal: premium,
            size: contractVolume,
            sentiment: sentiment,
            flowType: flowType,
            itm: isITM,
            stockPrice: price,
            timeAgo: timeAgo,
            timestamp: now - (minutesAgo * 60 * 1000),
          });
        }
      }
    }
    
    // Sort by expiration date first, then strike price
    // This groups all strikes together for each expiration date
    optionsData.sort((a, b) => {
      if (a.expiration !== b.expiration) {
        return new Date(a.expiration) - new Date(b.expiration);
      }
      return a.strike - b.strike;
    });
    
    res.json({
      ok: true,
      symbol: symbol,
      stockPrice: round2(price),
      stockChange: round2(pricePct),
      count: optionsData.length,
      results: optionsData.slice(0, limit),
      timestamp: now,
      disclaimer: "⚠️ EDUCATIONAL PURPOSE: This options flow data is simulated from stock market activity for learning and analysis. Not real-time options order flow from exchanges. Use for pattern recognition and strategy education only.",
    });
    
  } catch (e) {
    console.error("[api/options/flow] Error:", e);
    res.status(500).json({ ok: false, error: "Failed to fetch option flow", detail: String(e?.message || e) });
  }
});

// --------------------------------------------------------------------------
// Earnings Call Transcripts (FMP API)
// --------------------------------------------------------------------------
app.get("/earnings-transcripts", requireLogin, async (req, res) => {
  try {
    const symbol = String(req.query.symbol || "").trim().toUpperCase();
    const year = req.query.year ? String(req.query.year) : null;
    const quarter = req.query.quarter ? String(req.query.quarter) : null;
    const limit = clamp(Number(req.query.limit || 10), 1, 100);

    if (!symbol) {
      return res.status(400).json({ ok: false, error: "Missing required parameter: symbol" });
    }

    if (!FMP_API_KEY) {
      return res.status(500).json({ ok: false, error: "FMP_API_KEY not configured" });
    }

    // Build URL based on whether year/quarter are specified
    let url;
    if (year && quarter) {
      // Get specific quarter transcript
      url = `https://financialmodelingprep.com/api/v4/earning_call_transcript?symbol=${symbol}&year=${year}&quarter=${quarter}`;
    } else {
      // Get list of available transcripts
      url = `https://financialmodelingprep.com/api/v3/earning_call_transcript?symbol=${symbol}`;
    }

    const result = await safeGet(url, {
      params: { apikey: FMP_API_KEY },
      headers: { "user-agent": "ALGTP" },
    });

    if (!result.ok) {
      return res.status(result.status || 500).json({
        ok: false,
        error: "Failed to fetch earnings transcripts",
        detail: result.errorDetail,
      });
    }

    // Handle response data
    let transcripts = [];
    if (Array.isArray(result.data)) {
      transcripts = result.data.slice(0, limit);
    } else if (result.data && typeof result.data === "object") {
      // Single transcript response
      transcripts = [result.data];
    }

    // Format response
    const formatted = transcripts.map((t) => ({
      symbol: t.symbol || symbol,
      quarter: t.quarter || null,
      year: t.year || null,
      date: t.date || null,
      content: t.content || null,
      // Include metadata if available
      companyName: t.companyName || null,
      cik: t.cik || null,
    }));

    res.json({
      ok: true,
      symbol,
      year: year || undefined,
      quarter: quarter || undefined,
      count: formatted.length,
      results: formatted,
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "earnings-transcripts failed", detail: String(e?.message || e) });
  }
});

// --------------------------------------------------------------------------
// Earnings Calendar (FMP API)
// --------------------------------------------------------------------------
app.get("/earnings-calendar", requireLogin, async (req, res) => {
  try {
    const from = req.query.from || null; // YYYY-MM-DD format
    const to = req.query.to || null;     // YYYY-MM-DD format
    const symbol = req.query.symbol ? String(req.query.symbol).trim().toUpperCase() : null;

    if (!FMP_API_KEY) {
      return res.status(500).json({ ok: false, error: "FMP_API_KEY not configured" });
    }

    // Build URL - use stable API (legacy v3 deprecated August 2025)
    let url;
    if (symbol) {
      // Get earnings for specific symbol - try earnings-surprise for historical data
      url = `https://financialmodelingprep.com/stable/earnings-surprise?symbol=${symbol}`;
    } else if (from && to) {
      // Get earnings calendar for date range
      url = `https://financialmodelingprep.com/stable/earning-calendar?from=${from}&to=${to}`;
    } else {
      // Default: upcoming earnings (next 7 days)
      const today = new Date();
      const nextWeek = new Date(today.getTime() + 7 * 24 * 60 * 60 * 1000);
      const fromDate = today.toISOString().split('T')[0];
      const toDate = nextWeek.toISOString().split('T')[0];
      url = `https://financialmodelingprep.com/stable/earning-calendar?from=${fromDate}&to=${toDate}`;
    }

    const params = { apikey: FMP_API_KEY };
    if (!symbol && from && to) {
      params.from = from;
      params.to = to;
    }

    const result = await safeGet(url, {
      params,
      headers: { "user-agent": "ALGTP" },
    });

    if (!result.ok) {
      return res.status(result.status || 500).json({
        ok: false,
        error: "Failed to fetch earnings calendar",
        detail: result.errorDetail,
      });
    }

    // Handle response data
    let calendar = [];
    if (Array.isArray(result.data)) {
      calendar = result.data;
    } else if (result.data && typeof result.data === "object") {
      calendar = [result.data];
    }

    // Format and enrich response
    const formatted = calendar.map((event) => ({
      symbol: event.symbol || null,
      companyName: event.name || null,
      date: event.date || null,
      time: event.time || null,
      fiscalDateEnding: event.fiscalDateEnding || null,
      eps: event.eps !== undefined ? n(event.eps) : null,
      epsEstimated: event.epsEstimated !== undefined ? n(event.epsEstimated) : null,
      revenue: event.revenue !== undefined ? n(event.revenue) : null,
      revenueEstimated: event.revenueEstimated !== undefined ? n(event.revenueEstimated) : null,
      // Calculate surprise %
      epsSurprise: event.eps && event.epsEstimated ? 
        round2(((n(event.eps) - n(event.epsEstimated)) / Math.abs(n(event.epsEstimated))) * 100) : null,
      revenueSurprise: event.revenue && event.revenueEstimated ?
        round2(((n(event.revenue) - n(event.revenueEstimated)) / n(event.revenueEstimated)) * 100) : null,
      updatedFromDate: event.updatedFromDate || null,
    }));

    // Sort by date (upcoming first)
    formatted.sort((a, b) => {
      const dateA = new Date(a.date || 0);
      const dateB = new Date(b.date || 0);
      return dateA - dateB;
    });

    res.json({
      ok: true,
      symbol: symbol || undefined,
      from: from || undefined,
      to: to || undefined,
      count: formatted.length,
      results: formatted,
      note: symbol ? `Historical earnings for ${symbol}` : "Earnings calendar sorted by date",
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "earnings-calendar failed", detail: String(e?.message || e) });
  }
});

