// --------------------------------------------------------------------------
// Options Chain for Mobile App (stocks with ATM call/put strikes)
// --------------------------------------------------------------------------
app.get("/options-chain", async (req, res) => {
  try {
    const limit = clamp(Number(req.query.limit || 20), 5, 50);
    
    // Get top movers to show their options
    const base = ENABLE_SNAPSHOT_ALL
      ? await buildRowsFromSnapshotAll({ cap: "all", limit: limit * 2, session: null, sortMode: "active" })
      : await buildRowsFromMoversUnion({ cap: "all", limit: limit * 2, sortMode: "active" });

    if (!base.ok || !base.body?.results) {
      return res.json({ ok: true, results: [], note: "No stocks available" });
    }

    let stocks = base.body.results.slice(0, limit);
    
    // For each stock, show ATM call and put as separate "stocks"
    const optionsChain = [];
    const now = Date.now();
    
    for (const stock of stocks) {
      const price = n(stock.price) || n(stock.prevClose) || 0;
      if (price <= 0) continue;
      
      const pricePct = n(stock.pricePct) || 0;
      const volume = n(stock.volume) || 0;
      const gapPct = n(stock.gapPct) || 0;
      
      // Calculate ATM strike (round to nearest $1, $5, or $10)
      let strikeRound = 1;
      if (price < 5) strikeRound = 0.5;
      else if (price < 20) strikeRound = 1;
      else if (price < 100) strikeRound = 5;
      else strikeRound = 10;
      
      const atmStrike = round2(Math.round(price / strikeRound) * strikeRound);
      
      // Simple option pricing
      const impliedVol = 0.30 + Math.abs(pricePct) * 0.01;
      const daysToExp = 30;
      const optionPrice = round2(price * impliedVol * Math.sqrt(daysToExp / 365) * 0.4);
      
      // CALL option
      optionsChain.push({
        symbol: `${stock.symbol}`,
        price: round2(atmStrike),  // Strike as "price"
        pricePct: round2(optionPrice),  // Option price as "change"
        gapPct: pricePct,  // Stock change
        volume: Math.round(volume / 100),  // Option volume estimate
        floatTurnoverPct: 0,
        prevClose: round2(price),  // Stock price in prevClose
        floatM: null,
        marketCapB: null,
        cap: "CALL",
        session: "30D",
        gapSource: "CALL",
        floatSource: `Strike $${atmStrike}`,
        capSource: stock.symbol,
      });
      
      // PUT option
      optionsChain.push({
        symbol: `${stock.symbol}`,
        price: round2(atmStrike),  // Strike as "price"
        pricePct: round2(optionPrice * 0.9),  // Put typically cheaper
        gapPct: -pricePct,  // Inverse for puts
        volume: Math.round(volume / 120),
        floatTurnoverPct: 0,
        prevClose: round2(price),  // Stock price
        floatM: null,
        marketCapB: null,
        cap: "PUT",
        session: "30D",
        gapSource: "PUT",
        floatSource: `Strike $${atmStrike}`,
        capSource: stock.symbol,
      });
    }
    
    // Sort by stock volume (most active first)
    optionsChain.sort((a, b) => (b.volume || 0) - (a.volume || 0));
    
    res.json({
      ok: true,
      mode: "options_chain",
      count: optionsChain.length,
      results: optionsChain,
      note: "⛓️ ATM options chain (30-day calls & puts). Strike shown as price, option premium as change%.",
    });
  } catch (e) {
    console.error("[options-chain] Error:", e);
    res.json({ ok: true, results: [], error: String(e?.message || e) });
  }
});

