// Earnings Calendar (by date range)
// GET /box/fmp-earnings-calendar?from=2025-02-01&to=2025-03-01&page=0&limit=100
// --------------------------------------------------------------------------
app.get("/box/fmp-earnings-calendar", requireLogin, requireAccess, async (req, res) => {
  try {
    const from = String(req.query.from || "").trim();
    const to = String(req.query.to || "").trim();
    const page = clamp(Number(req.query.page || 0), 0, 200);
    const limit = clamp(Number(req.query.limit || 100), 1, 500);

    if (!from || !to) {
      return res.status(400).json({ ok: false, error: "from/to required (YYYY-MM-DD)" });
    }

    if (!FMP_API_KEY) {
      return res.status(500).json({ ok: false, error: "FMP_API_KEY not configured" });
    }

    // Try stable API first
    let url = `https://financialmodelingprep.com/stable/earnings-calendar`;
    let result = await safeGet(url, {
      params: { from, to, page, limit, apikey: FMP_API_KEY },
      headers: { "user-agent": "ALGTP" },
    });

    // Fallback to v3 API if stable not available
    if (!result.ok || (result.status && result.status >= 400)) {
      url = `https://financialmodelingprep.com/api/v3/earning_calendar`;
      result = await safeGet(url, {
        params: { from, to, apikey: FMP_API_KEY },
        headers: { "user-agent": "ALGTP" },
      });
    }

    if (!result.ok) {
      return res.status(result.status || 500).json({
        ok: false,
        error: "FMP_EARNINGS_CALENDAR_FAILED",
        detail: result.errorDetail,
      });
    }

    const rows = Array.isArray(result.data) ? result.data : [];
    // Sort by date desc (most recent first)
    rows.sort((a, b) => String(b?.date || "").localeCompare(String(a?.date || "")));

    res.json({
      ok: true,
      source: "fmp.earnings-calendar",
      from,
      to,
      page,
      limit,
      count: rows.length,
      results: rows,
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "box/fmp-earnings-calendar failed", detail: String(e?.message || e) });
  }
});

// =============================================================================
// FMP Earnings Calendar — Specialized Views (Today, Tomorrow, Next 7, Watchlist)
// =============================================================================

// Helper: Get date in YYYY-MM-DD format (New York timezone)
function ymdNY(d = new Date()) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "America/New_York",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).formatToParts(d);
  const y = parts.find(p => p.type === "year")?.value || "1970";
  const m = parts.find(p => p.type === "month")?.value || "01";
  const dd = parts.find(p => p.type === "day")?.value || "01";
  return `${y}-${m}-${dd}`;
}

// Helper: Add days to current date (NY timezone)
function addDaysNY(n) {
  return ymdNY(new Date(Date.now() + n * 86400000));
}

// Helper: Fetch earnings calendar with fallback
async function fetchEarningsCalendarHelper({ from, to, page = 0, limit = 500 }) {
  if (!FMP_API_KEY) return { ok: false, status: 400, error: "missing_FMP_API_KEY" };

  // Try stable API first
  let url = `https://financialmodelingprep.com/stable/earnings-calendar`;
  let result = await safeGet(url, {
    params: { from, to, page, limit, apikey: FMP_API_KEY },
    headers: { "user-agent": "ALGTP" },
  });

  if (result.ok) return result;

  // Fallback to v3 API
  url = `https://financialmodelingprep.com/api/v3/earning_calendar`;
  result = await safeGet(url, {
    params: { from, to, apikey: FMP_API_KEY },
    headers: { "user-agent": "ALGTP" },
  });

  return result;
}

// Helper: Normalize earnings row
function normEarningsRow(x) {
  return {
    symbol: x.symbol ?? x.ticker ?? null,
    date: x.date ?? null,
    epsEstimated: x.epsEstimated ?? x.epsEstimate ?? null,
    epsActual: x.epsActual ?? null,
    revenueEstimated: x.revenueEstimated ?? x.revenueEstimate ?? null,
    revenueActual: x.revenueActual ?? null,
    lastUpdated: x.lastUpdated ?? null,
    time: x.time ?? x.hour ?? null,
  };
}

// --------------------------------------------------------------------------
// Earnings — Today
// GET /box/fmp-earnings-today?limit=300
// --------------------------------------------------------------------------
app.get("/box/fmp-earnings-today", requireLogin, requireAccess, async (req, res) => {
  try {
    const from = ymdNY();
    const to = from;
    const limit = clamp(Number(req.query.limit || 300), 10, 1000);

    const out = await fetchEarningsCalendarHelper({ from, to, page: 0, limit });
    if (!out.ok) {
      return res.status(out.status || 500).json({
        ok: false,
        error: "FMP_EARNINGS_TODAY_FAILED",
        detail: out.errorDetail || out,
      });
    }

    const rows = (Array.isArray(out.data) ? out.data : [])
      .map(normEarningsRow)
      .filter(r => r.symbol && r.date);

    rows.sort((a, b) => String(a.symbol).localeCompare(String(b.symbol)));

    res.json({
      ok: true,
      box: "earnings_today",
      from,
      to,
      count: rows.length,
      results: rows.slice(0, limit),
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "earnings-today failed", detail: String(e?.message || e) });
  }
});

