// --------------------------------------------------------------------------
// Economic Calendar (Public - for widget)
// GET /economic-calendar-widget?limit=10
// --------------------------------------------------------------------------
app.get("/economic-calendar-widget", async (req, res) => {
  try {
    const limit = clamp(Number(req.query.limit || 10), 1, 50);

    // Fallback data if API unavailable
    const fallbackEvents = [
      { event: "FOMC Meeting Minutes", date: "2026-02-28", time: "14:00:00", country: "US", impact: "HIGH" },
      { event: "Nonfarm Payrolls", date: "2026-03-07", time: "08:30:00", country: "US", impact: "HIGH" },
      { event: "CPI m/m", date: "2026-03-12", time: "08:30:00", country: "US", impact: "HIGH" },
      { event: "Retail Sales m/m", date: "2026-03-15", time: "08:30:00", country: "US", impact: "HIGH" },
      { event: "FOMC Economic Projections", date: "2026-03-19", time: "14:00:00", country: "US", impact: "HIGH" },
    ];

    if (!FMP_API_KEY) {
      return res.json({
        ok: true,
        count: fallbackEvents.length,
        results: fallbackEvents,
        note: "Using fallback data - FMP_API_KEY not configured"
      });
    }

    // Fetch next 30 days
    const from = new Date().toISOString().split('T')[0];
    const to = new Date(Date.now() + 30 * 86400000).toISOString().split('T')[0];

    const url = `https://financialmodelingprep.com/api/v3/economic_calendar`;
    const result = await safeGet(url, {
      params: { from, to, apikey: FMP_API_KEY },
      headers: { "user-agent": "ALGTP" },
      timeout: 5000, // 5 second timeout
    });

    if (!result.ok) {
      console.warn("Economic calendar API failed, using fallback data");
      return res.json({
        ok: true,
        count: fallbackEvents.length,
        results: fallbackEvents,
        note: "Using fallback data - API request failed"
      });
    }

    let rows = Array.isArray(result.data) ? result.data : [];
    
    // Format and filter for US high-impact events
    const formatted = rows
      .map(event => ({
        event: event.event || null,
        date: event.date ? event.date.split(' ')[0] : null,
        time: event.date ? event.date.split(' ')[1] : null,
        country: event.country || null,
        actual: event.actual ?? null,
        previous: event.previous ?? null,
        estimate: event.estimate ?? null,
        impact: event.impact || (event.estimate !== null ? 'HIGH' : 'MEDIUM'),
      }))
      .filter(e => e.country === 'US' && (e.impact === 'HIGH' || e.estimate !== null));

    // Sort by date ascending (upcoming first)
    formatted.sort((a, b) => String(a.date || "").localeCompare(String(b.date || "")));

    // If no events found, use fallback
    if (formatted.length === 0) {
      return res.json({
        ok: true,
        count: fallbackEvents.length,
        results: fallbackEvents,
        note: "Using fallback data - no US events found"
      });
    }

    res.json({
      ok: true,
      count: Math.min(formatted.length, limit),
      results: formatted.slice(0, limit),
    });
  } catch (e) {
    console.warn("Economic calendar widget error:", e.message);
    // Return fallback data on error
    const fallbackEvents = [
      { event: "FOMC Meeting Minutes", date: "2026-02-28", time: "14:00:00", country: "US", impact: "HIGH" },
      { event: "Nonfarm Payrolls", date: "2026-03-07", time: "08:30:00", country: "US", impact: "HIGH" },
      { event: "CPI m/m", date: "2026-03-12", time: "08:30:00", country: "US", impact: "HIGH" },
    ];
    res.json({
      ok: true,
      count: fallbackEvents.length,
      results: fallbackEvents,
      note: "Using fallback data - error occurred"
    });
  }
});

// --------------------------------------------------------------------------
// Economic Calendar (Premium - full access)
