// --------------------------------------------------------------------------
app.get("/box/fmp-economic-calendar", requireLogin, requireAccess, async (req, res) => {
  try {
    const from = req.query.from || new Date(Date.now()).toISOString().split('T')[0];
    const to = req.query.to || new Date(Date.now() + 30 * 86400000).toISOString().split('T')[0];
    const limit = clamp(Number(req.query.limit || 100), 1, 500);

    if (!FMP_API_KEY) {
      return res.status(500).json({ ok: false, error: "FMP_API_KEY not configured" });
    }

    // Use v3 API for economic calendar
    const url = `https://financialmodelingprep.com/api/v3/economic_calendar`;
    const result = await safeGet(url, {
      params: { from, to, apikey: FMP_API_KEY },
      headers: { "user-agent": "ALGTP" },
    });

    if (!result.ok) {
      return res.status(result.status || 500).json({
        ok: false,
        error: "FMP_ECONOMIC_CALENDAR_FAILED",
        detail: result.errorDetail,
      });
    }

    let rows = Array.isArray(result.data) ? result.data : [];
    
    // Format response with impact categorization
    const formatted = rows.map(event => ({
      event: event.event || null,
      date: event.date ? event.date.split(' ')[0] : null, // Extract date part
      time: event.date ? event.date.split(' ')[1] : null, // Extract time part
      country: event.country || null,
      actual: event.actual ?? null,
      previous: event.previous ?? null,
      estimate: event.estimate ?? null,
      change: event.change ?? null,
      changePercentage: event.changePercentage ?? null,
      impact: event.impact || (event.estimate !== null ? 'HIGH' : 'MEDIUM'), // Estimate availability = high impact
    }));

    // Sort by date desc (most recent first)
    formatted.sort((a, b) => String(b?.date || "").localeCompare(String(a?.date || "")));

    res.json({
      ok: true,
      source: "fmp.economic-calendar",
      from,
      to,
      count: Math.min(formatted.length, limit),
      results: formatted.slice(0, limit),
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "box/fmp-economic-calendar failed", detail: String(e?.message || e) });
  }
});

