// --------------------------------------------------------------------------
// Analyst Ratings & Price Targets (FMP API)
// --------------------------------------------------------------------------
app.get("/analyst-ratings", requireLogin, async (req, res) => {
  try {
    const symbol = req.query.symbol ? String(req.query.symbol).trim().toUpperCase() : null;
    const limit = clamp(Number(req.query.limit || 100), 1, 1000);
    const type = req.query.type || null; // upgrade, downgrade, initiated, reiterated

    if (!FMP_API_KEY) {
      return res.status(500).json({ ok: false, error: "FMP_API_KEY not configured" });
    }

    // If no symbol, get latest upgrades/downgrades across all stocks
    const url = symbol 
      ? `https://financialmodelingprep.com/api/v3/grade/${symbol}`
      : `https://financialmodelingprep.com/api/v3/upgrades-downgrades-grading-company`;

    const result = await safeGet(url, {
      params: { apikey: FMP_API_KEY, limit },
      headers: { "user-agent": "ALGTP" },
    });

    if (!result.ok) {
      return res.status(result.status || 500).json({
        ok: false,
        error: "Failed to fetch analyst ratings",
        detail: result.errorDetail,
      });
    }

    const ratings = Array.isArray(result.data) ? result.data : [];
    
    // Filter by type if specified
    let filtered = ratings;
    if (type) {
      const typeUpper = String(type).toUpperCase();
      filtered = ratings.filter(r => {
        const action = String(r.newGrade || r.newRating || "").toUpperCase();
        if (typeUpper === "UPGRADE") return action.includes("UPGRADE") || action.includes("BUY") || action.includes("OUTPERFORM");
        if (typeUpper === "DOWNGRADE") return action.includes("DOWNGRADE") || action.includes("SELL") || action.includes("UNDERPERFORM");
        return true;
      });
    }
    
    const formatted = filtered.slice(0, limit).map((r) => ({
      symbol: r.symbol || null,
      date: r.date || r.publishedDate || null,
      gradingCompany: r.gradingCompany || r.analystCompany || null,
      previousGrade: r.previousGrade || null,
      newGrade: r.newGrade || null,
      previousRating: r.previousRating || null,
      newRating: r.newRating || r.action || null,
    }));

    res.json({
      ok: true,
      symbol: symbol || "market-wide",
      type: type || "all",
      count: formatted.length,
      results: formatted,
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "analyst-ratings failed", detail: String(e?.message || e) });
  }
});

