app.get("/institutional-holdings", requireLogin, async (req, res) => {
  try {
    const symbol = req.query.symbol ? String(req.query.symbol).trim().toUpperCase() : null;

    if (!symbol) {
      return res.status(400).json({ ok: false, error: "Missing required parameter: symbol" });
    }

    if (!FMP_API_KEY) {
      return res.status(500).json({ ok: false, error: "FMP_API_KEY not configured" });
    }

    const url = `https://financialmodelingprep.com/api/v3/institutional-holder/${symbol}`;

    const result = await safeGet(url, {
      params: { apikey: FMP_API_KEY },
      headers: { "user-agent": "ALGTP" },
    });

    if (!result.ok) {
      return res.status(result.status || 500).json({
        ok: false,
        error: "Failed to fetch institutional holdings",
        detail: result.errorDetail,
      });
    }

    const holdings = Array.isArray(result.data) ? result.data : [];
    const formatted = holdings.map((h) => ({
      holder: h.holder || null,
      shares: h.shares ? Math.round(n(h.shares)) : null,
      dateReported: h.dateReported || null,
      change: h.change ? Math.round(n(h.change)) : null,
      changePercent: h.changePercent ? round2(n(h.changePercent)) : null,
      putCall: h.putCall || null,
    }));

    res.json({
      ok: true,
      symbol,
      count: formatted.length,
      results: formatted,
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: "institutional-holdings failed", detail: String(e?.message || e) });
  }
});

// =======================================================
// ✅ Sector Screener (Massive Movers + FMP Profile)
// GET /box/sector-screener-advanced?sector=Technology&minPrice=2&maxPrice=50&minVolume=1000000&cap=all&limit=200
// Rank: abs(Gap%) desc -> Momentum desc
// Uses: Massive movers list + FMP profile endpoint for sector classification
// =======================================================

// Sector profile cache to reduce FMP API calls
const sectorProfileCache = new Map(); // sym -> {ts, sector, industry}
const SECTOR_CACHE_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

// Fetch sector info from FMP profile endpoint
async function fetchSectorProfile(sym) {
  if (!FMP_API_KEY) {
    console.warn(`fetchSectorProfile(${sym}): FMP_API_KEY not set`);
    return null;
  }
  
  const cached = sectorProfileCache.get(sym);
  if (cached && (Date.now() - cached.ts) < SECTOR_CACHE_TTL_MS) {
    return cached.sector;
  }
  
  try {
    const url = `https://financialmodelingprep.com/api/v3/profile/${sym}`;
    const result = await safeGet(url, {
      params: { apikey: FMP_API_KEY },
      headers: { "user-agent": "ALGTP" },
    });
    
    if (!result.ok) {
      console.warn(`fetchSectorProfile(${sym}): API error ${result.status}`, result.errorDetail?.message);
      return null;
    }
    
    if (!Array.isArray(result.data) || result.data.length === 0) {
      console.warn(`fetchSectorProfile(${sym}): No profile data returned`);
      return null;
    }
    
    const profile = result.data[0];
    const sector = String(profile?.sector || "").trim();
    const industry = String(profile?.industry || "").trim();
    
    if (!sector) {
      console.warn(`fetchSectorProfile(${sym}): Profile exists but no sector field`);
    }
    
    sectorProfileCache.set(sym, { ts: Date.now(), sector, industry });
    return sector || null;
  } catch (e) {
    console.error(`fetchSectorProfile(${sym}) exception:`, e.message);
    return null;
  }
}

app.get("/box/sector-screener-advanced", requireLogin, requireAccess, async (req, res) => {
  try {
    const sector = String(req.query.sector || "").trim();
    if (!sector) return res.status(400).json({ ok:false, error:"sector required" });

    const minPrice = Number(req.query.minPrice || 0);
    const maxPrice = Number(req.query.maxPrice || 100000);
    const minVolume = Number(req.query.minVolume || 0);
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = Math.max(20, Math.min(1000, Number(req.query.limit || 200)));
    const maxFloatM = Number(req.query.maxFloatM || 20); // Default: Low Float < 20M

    if (!MASSIVE_API_KEY) {
      return res.status(500).json({ ok: false, error: "MASSIVE_API_KEY not configured" });
    }

    // 1) Get universe from Massive movers (combined: gainers + losers)
    const g = await fetchMovers("gainers");
    const l = await fetchMovers("losers");
    
    const pool = [...(g.ok ? g.rows : []), ...(l.ok ? l.rows : [])]
      .map((x) => String(x?.ticker ?? x?.symbol ?? x?.sym ?? "").trim().toUpperCase())
      .filter(Boolean);
    
    const tickers = Array.from(new Set(pool)).slice(0, 500);
    if (!tickers.length) {
      return res.json({ ok:true, sector, count:0, results: [] });
    }

    // 2) Snapshot from Massive (your existing function)
    const snaps = await mapPool(tickers, SNAP_CONCURRENCY, async (t) => {
      const r = await fetchTickerSnapshot(t);
      return { ticker: t, ...r };
    });

    const good = snaps.filter(x => x.ok);
    let rows = good.map(x => normalizeSnapshotAuto(x.ticker, x.data)).map(addExtPctFromPrevClose);

    // 2a) Price and volume filters (pre-filter before sector lookup)
    rows = rows.filter(r => {
      const price = n(r?.price);
      const volume = n(r?.volume);
      return (
        price !== null && price >= minPrice && price <= maxPrice &&
        volume !== null && volume >= minVolume
      );
    });

    // Cap filter
    rows = rows.filter(r => capPass(r, cap));

    // 2b) Sector filter using FMP profile endpoint
    if (FMP_API_KEY) {
      console.log(`Fetching sector info for ${rows.length} symbols...`);
      
      const sectorResults = await mapPool(rows, Math.min(SNAP_CONCURRENCY, 3), async (r) => {
        const sym = String(r?.symbol || "").trim().toUpperCase();
        const symSector = await fetchSectorProfile(sym);
        return { ...r, sector: symSector };
      });
      
      // Filter by target sector (case-insensitive partial match)
      // IMPORTANT: Reject symbols with missing/null sector info
      const targetSector = sector.toLowerCase();
      rows = sectorResults.filter(r => {
        const rowSector = String(r?.sector || "").trim().toLowerCase();
        
        // Reject if sector is empty/missing
        if (!rowSector) {
          console.log(`  ❌ ${r.symbol}: no sector info`);
          return false;
        }
        
        // Match if either sector contains the other (partial match)
        const matches = rowSector.includes(targetSector) || targetSector.includes(rowSector);
        if (matches) {
          console.log(`  ✅ ${r.symbol}: ${rowSector} matches ${targetSector}`);
        }
        return matches;
      });
      
      console.log(`Sector filter: ${sectorResults.length} -> ${rows.length} (target: ${sector})`);
    } else {
      console.warn("⚠️  FMP_API_KEY not set - sector filtering skipped");
      rows = [];
    }

    if (!rows.length) {
      return res.json({ ok:true, sector, count:0, results: [], message: "No symbols match sector filter" });
    }

    // 3) Overwrite Gap% using Polygon (your function)
    rows = await enrichRowsWithDailyOpen(rows, 200);

    // 4) Float enrich (REQUIRED for float filter)
    if (ENABLE_FLOAT_ENRICH && FMP_API_KEY) {
      rows = await enrichRowsWithFloat(rows, 200);
    }

    // 4b) Low Float filter (Day Trader mode)
    if (maxFloatM && maxFloatM < 1000000) {
      rows = rows.filter(r => {
        const floatM = Number(r?.floatM);
        return Number.isFinite(floatM) && floatM > 0 && floatM <= maxFloatM;
      });
    }

    // 5) Indicators -> score/paIcon/signalIcon (optional, but good for momentum)
    if (ENABLE_5M_INDICATORS) {
      const { rows: withInd } = await attachIndicatorsIfEnabled(rows);
      rows = finalizeRows(withInd);
    }

    // 6) Rank: Gap% first, then Momentum (Day Trader style)
    const num = (v)=> (Number.isFinite(Number(v)) ? Number(v) : 0);
    rows.sort((a,b)=>{
      // Gap% ranking (absolute value, descending)
      const g = Math.abs(num(b?.gapPct)) - Math.abs(num(a?.gapPct));

      // Momentum: score > volRatio_5m > floatTurnoverPct > volume
      const momA = num(a?.score) || num(a?.volRatio_5m) || num(a?.floatTurnoverPct) || num(a?.volume);
      const momB = num(b?.score) || num(b?.volRatio_5m) || num(b?.floatTurnoverPct) || num(b?.volume);

      return g || (momB - momA);
    });

    rows = rows.slice(0, limit);

    res.json({
      ok:true,
      sector,
      filters: { minPrice, maxPrice, minVolume, cap, maxFloatM },
      rank: "abs(gapPct) desc → momentum desc(score/rovl/floatTurn/vol)",
      count: rows.length,
      results: rows
    });

  } catch (e) {
    res.status(500).json({ ok:false, error:"sector-screener-advanced failed", detail:String(e?.message||e) });
  }
});

