    const base = ENABLE_SNAPSHOT_ALL
      ? await buildRowsFromSnapshotAll({ cap, limit: Math.max(250, limit * 5), session: null, sortMode: "active" })
      : await buildRowsFromMoversUnion({ cap, limit: Math.max(250, limit * 5), sortMode: "active" });

