let riskAccepted = false;
(function riskNotice(){
  const back = byId("riskBack");
  const agree = byId("riskAgree");
  const btn = byId("riskContinueBtn");
  const hint = byId("riskHint");
  back.style.display = "flex";
  btn.disabled = true;

  agree.addEventListener("change", () => {
    btn.disabled = !agree.checked;
    hint.style.display = agree.checked ? "none" : "block";
  });

  btn.addEventListener("click", () => {
    if (!agree.checked) { hint.style.display = "block"; return; }
    riskAccepted = true;
    back.style.display = "none";
    trackEvent("risk_notice_accepted");
  });
})();
function riskIsOpen(){ return !riskAccepted; }

function showError(obj){
  errBox.style.display = "block";
  errBox.textContent = typeof obj === "string" ? obj : JSON.stringify(obj, null, 2);
}
function clearError(){ errBox.style.display = "none"; errBox.textContent = ""; }

function fmtNum(x, digits=2){
  if (x === null || x === undefined) return "-";
  const nn = Number(x);
  if (!Number.isFinite(nn)) return "-";
  return nn.toFixed(digits);
}
function fmtInt(x){
  if (x === null || x === undefined) return "-";
  const nn = Number(x);
  if (!Number.isFinite(nn)) return "-";
  return Math.round(nn).toLocaleString();
}

// ✅ TradingView URL: Normalize symbol with exchange prefix
function tvUrlFor(sym){
  const s = String(sym || "").trim().toUpperCase();
  // If symbol already has exchange prefix (e.g. "NASDAQ:AAPL", "NYSE:TSLA"), keep it
  // Otherwise, add "NASDAQ:" prefix (most US stocks)
  const fixed = s.includes(":") ? s : ("NASDAQ:" + s);
  return "https://www.tradingview.com/chart/?symbol=" + encodeURIComponent(fixed) + "&interval=5";
}
window.handleTickerClick = function(ev, sym){
  const symbol = String(sym || "").trim().toUpperCase();
  
  // 🔥 NEW: Update TradingView chart (if function exists)
  if (typeof updateTVSymbol === "function") {
    updateTVSymbol(symbol);
  }
  
  // ✅ Open Stock Hub modal instead of new tab (prevents popup blocking)
  trackEvent("symbol_click", { symbol: symbol, featureId: "stockhub_modal" });
  tvHubOpen(symbol);
};

// hover mini chart - SINGLETON PATTERN with proper cleanup
let miniBox=null, miniChart=null, candle=null, lineEMA9=null, lineEMA34=null, lineSMA26=null, lineVWAP=null;
let miniSym=null, hoverTimer=null;
let miniChartInitialized = false; // Track if chart is initialized
let miniChartInitializing = false; // Prevent concurrent init
const miniCache = new Map();

// Cleanup function to properly destroy chart instance
function destroyMiniChart() {
  if (miniChart) {
    try {
      miniChart.remove();
      console.log("[miniChart] Destroyed previous instance");
    } catch(e) {
      console.warn("[miniChart] Destroy failed:", e);
    }
    miniChart = null;
    candle = null;
    lineEMA9 = null;
    lineEMA34 = null;
    lineSMA26 = null;
    lineVWAP = null;
    miniChartInitialized = false;
  }
}

function ensureMiniBox(){
  if (miniBox) return;
  miniBox=document.createElement("div");
  miniBox.id = "miniChartPopup"; // Unique ID to prevent duplicates
  miniBox.style.position="fixed";
  miniBox.style.width="380px";
  miniBox.style.height="250px";
  miniBox.style.background="#0b0d12";
  miniBox.style.border="1px solid rgba(255,255,255,.18)";
  miniBox.style.borderRadius="16px";
  miniBox.style.boxShadow="0 18px 70px rgba(0,0,0,.55)";
  miniBox.style.padding="10px";
  miniBox.style.zIndex="110";
  miniBox.style.display="none";
  miniBox.innerHTML='<div id="miniTitle" style="font-weight:900;font-size:12px;margin-bottom:6px;"></div><div id="miniChartContainer" style="width:100%;height:190px;"></div><div style="margin-top:6px;font-size:11px;color:#a7adc2">Hover = mini chart • Click = Stock Hub</div>';
  
  // Remove any existing popup with same ID (prevent duplicates on page refresh)
  const existing = document.getElementById("miniChartPopup");
  if (existing) {
    existing.remove();
    console.log("[miniChart] Removed existing popup");
  }
  
  document.body.appendChild(miniBox);
  // NOTE: Chart creation is deferred to initMiniChart() - must be called AFTER popup is visible
}

// Initialize chart ONLY when popup is visible (clientWidth/Height > 0)
function initMiniChart(){
  // Prevent double initialization
  if (miniChartInitialized || miniChartInitializing) return;
  
  const el = miniBox?.querySelector("#miniChartContainer");
  if (!el) return;
  
  // Check if container has dimensions (must be visible)
  const w = el.clientWidth, h = el.clientHeight;
  if (w < 10 || h < 10) {
    console.warn("[miniChart] Cannot init - container not visible:", w, h);
    return;
  }
  
  // Clear any existing content in container (prevents iframe duplication)
  el.innerHTML = "";
  
  miniChartInitializing = true;
  
  try {
    miniChart = LightweightCharts.createChart(el, {
      width: w,
      height: h,
      layout: { background: { type: "solid", color: "#0b0d12" }, textColor: "#c8cde0" },
      grid: { vertLines: { visible: false }, horzLines: { visible: false } },
      rightPriceScale: { visible: true },
      timeScale: { visible: false },
      crosshair: { mode: 0 },
    });
    candle = miniChart.addCandlestickSeries();
    lineEMA9  = miniChart.addLineSeries({ color: '#22c55e', lineWidth: 1 });
    lineEMA34 = miniChart.addLineSeries({ color: '#f59e0b', lineWidth: 1 });
    lineSMA26 = miniChart.addLineSeries({ color: '#8b5cf6', lineWidth: 1 });
    lineVWAP  = miniChart.addLineSeries({ color: '#60a5fa', lineWidth: 2, lineStyle: 2 });
    miniChartInitialized = true;
    console.log("[miniChart] Initialized successfully:", w, "x", h);
  } catch(e){
    console.error("[miniChart] Init failed:", e);
  } finally {
    miniChartInitializing = false;
  }
}

function posMini(ev){
  if (!miniBox) return;
  const pad=12;
  let x=ev.clientX+pad, y=ev.clientY+pad;
  const w=400,h=270;
  if (x+w>window.innerWidth) x=ev.clientX-w-pad;
  if (y+h>window.innerHeight) y=ev.clientY-h-pad;
  miniBox.style.left=x+"px";
  miniBox.style.top=y+"px";
}

async function fetchMini(sym){
  if (miniCache.has(sym)) return miniCache.get(sym);
  try {
    const r = await fetch("/mini-chart?symbol="+encodeURIComponent(sym)+"&tf=1", {
      credentials: "same-origin"
    });
    const j = await r.json();
    if (!j.ok) return null;
    miniCache.set(sym,j);
    return j;
  } catch(e) {
    console.error("[miniChart] Fetch failed:", e);
    return null;
  }
}

// Debounce tracking to prevent rapid re-triggers
let lastShowMiniTime = 0;

async function showMini(ev, sym){
  // Debounce: prevent rapid re-triggers (min 100ms between calls)
  const now = Date.now();
  if (now - lastShowMiniTime < 100) return;
  lastShowMiniTime = now;
  
  ensureMiniBox();
  miniSym=sym;
  posMini(ev);
  miniBox.style.display="block"; // Make visible FIRST
  miniBox.querySelector("#miniTitle").textContent = "📈 " + sym + " — mini chart (loading...)";
  trackEvent("mini_chart_hover", { symbol: sym });

  // Initialize chart AFTER popup is visible (requires DOM to have dimensions)
  // Use requestAnimationFrame to ensure layout is computed
  requestAnimationFrame(() => {
    initMiniChart();
    
    // If chart still not initialized, try again after a short delay
    if (!miniChartInitialized && !miniChartInitializing) {
      setTimeout(() => initMiniChart(), 50);
    }
  });

  const data = await fetchMini(sym);
  
  // Check if user has moved to different symbol while fetching
  if (!data || miniSym!==sym) return;
  
  // Update title to show loaded
  if (miniBox) {
    miniBox.querySelector("#miniTitle").textContent = "📈 " + sym + " — mini chart";
  }

  // Only set data if chart is initialized
  if (miniChartInitialized && candle && miniChart) {
    try {
      candle.setData(data.ohlc||[]);
      lineEMA9.setData(data.overlays?.ema9||[]);
      lineEMA34.setData(data.overlays?.ema34||[]);
      lineSMA26.setData(data.overlays?.sma26||[]);
      lineVWAP.setData(data.overlays?.vwap||[]);
      miniChart.timeScale().fitContent();
    } catch(e) {
      console.error("[miniChart] setData failed:", e);
    }
  } else {
    console.warn("[miniChart] Chart not ready, data not displayed");
    if (miniBox) {
      miniBox.querySelector("#miniTitle").textContent = "📈 " + sym + " — chart loading...";
    }
  }
}

function hideMini(){ 
  miniSym=null; 
  if(miniBox) miniBox.style.display="none"; 
  // Note: We keep the chart instance alive for reuse (singleton pattern)
  // Only destroy on page unload or explicit cleanup
}

function bindMiniHover(){
  document.querySelectorAll(".symLink").forEach(a=>{
    const sym = a.getAttribute("data-sym") || a.textContent.trim();
    // Hover for mini chart
    a.onmouseenter = (ev)=>{ clearTimeout(hoverTimer); hoverTimer=setTimeout(()=>showMini(ev,sym),120); };
    a.onmousemove  = (ev)=>{ if(miniBox && miniBox.style.display==="block") posMini(ev); };
    a.onmouseleave = ()=>{ clearTimeout(hoverTimer); hideMini(); };
  });
}

// Cleanup mini chart on page unload to prevent ghost instances
window.addEventListener('beforeunload', () => {
  destroyMiniChart();
  if (miniBox) {
    miniBox.remove();
    miniBox = null;
  }
});

// Also cleanup when page visibility changes (tab switch)
document.addEventListener('visibilitychange', () => {
  if (document.hidden) {
    hideMini();
  }
});

