// Combined query params helper
function getCombinedQueryParams() {
  let params = '';
  
  // Add options flow params
  if (optionsFlowMode) {
    params += '&optionsflow=1&trackcontracts=1';
  }
  
  // Add dark pool params
  if (darkPoolMode) {
    params += '&darkpool=1&trackblocks=1';
  }
  
  // Add eco params
  if (ecoMode) {
    params += '&eco=1&cache=aggressive';
  }
  
  // Add turbo params
  if (turboMode) {
    params += '&turbo=1&boost=1';
  }
  
  return params;
}

