// Bell audio element
const bellAudio = new Audio("https://actions.google.com/sounds/v1/alarms/beep_short.ogg");
bellAudio.volume = 0.5;

// Track symbols per box to detect new ones
const boxSymbolMemory = {};

// 🆕 AUTO-ADD MEMORY PER BOX
const boxSeen = {};        // { boxId: Set(symbol) }  - symbols ever seen
const boxPinned = {};      // { boxId: Map(symbol -> row) } - pinned rows kept
const BOX_PIN_MAX = 60;    // max symbols kept per box
const BOX_PIN_TTL_MS = 30 * 60 * 1000; // auto-expire pinned after 30 min

// 🆕 GLOBAL NEW TICKERS TRACKING (across ALL boxes)
const NEW_BOX_ID = "new_tickers";
const globalTickersSeen = new Set();  // All symbols ever seen globally
const newTickersList = [];            // Array of { symbol, row, fromBox, firstSeen }
const NEW_TICKERS_MAX = 200;          // Max symbols to keep

function ensureBoxStore(boxId){
  if (!boxSeen[boxId]) boxSeen[boxId] = new Set();
  if (!boxPinned[boxId]) boxPinned[boxId] = new Map();
}

function prunePinned(boxId){
  const m = boxPinned[boxId];
  if (!m) return;
  const now = Date.now();

  // TTL cleanup (optional)
  for (const [sym, row] of m.entries()){
    const ts = Number(row?._pinnedAt || 0);
    if (ts && (now - ts) > BOX_PIN_TTL_MS) m.delete(sym);
  }

  // Size cap
  if (m.size > BOX_PIN_MAX){
    const arr = Array.from(m.entries()).sort((a,b)=> (a[1]?._pinnedAt||0) - (b[1]?._pinnedAt||0));
    const drop = arr.length - BOX_PIN_MAX;
    for (let i=0;i<drop;i++) m.delete(arr[i][0]);
  }
}

function clearBoxPinned(boxId){
  if (boxSeen[boxId]) boxSeen[boxId].clear();
  if (boxPinned[boxId]) boxPinned[boxId].clear();
  console.log("Cleared auto-added symbols for box:", boxId);
}

// 🆕 NEW TICKERS MANAGEMENT
function addNewTicker(row, fromBoxId){
  const sym = String(row?.symbol || "").trim().toUpperCase();
  if (!sym) return;
  
  // Skip if already seen globally
  if (globalTickersSeen.has(sym)) return;
  
  globalTickersSeen.add(sym);
  
  // Add to list with metadata
  newTickersList.unshift({
    symbol: sym,
    firstSeen: Date.now(),
    fromBox: fromBoxId || "",

    // 🔥 Keep trading data
    price: row?.price ?? null,
    gapPct: row?.gapPct ?? null,
    pricePct: row?.pricePct ?? null,
    volume: row?.volume ?? null,
    volRatio_5m: row?.volRatio_5m ?? null,
    floatTurnoverPct: row?.floatTurnoverPct ?? null,

    // ✅ Add signal, PA, and score
    signalIcon: row?.signalIcon || "",
    paIcon: row?.paIcon || "",
    score: row?.score ?? null,
    demandScore: row?.demandScore ?? null
  });
  
  // Prune old entries if exceeded max
  if (newTickersList.length > NEW_TICKERS_MAX) {
    newTickersList.splice(NEW_TICKERS_MAX);
  }
  
  // 🔔 Optional: Ring bell for new ticker
  // ringBell();
  
  console.log("🆕 NEW TICKER:", sym, "from", fromBoxId);
}

function clearNewTickers(){
  globalTickersSeen.clear();
  newTickersList.length = 0;
  console.log("🆕 Cleared all NEW TICKERS");
}

// ============================================================================
// 🔥 VWAP BREAK AUTO-ADD STORE (client-side)
// ============================================================================
const VWAP_BOX_ID = "vwap_break_box";
const vwapSeen = new Set();              // symbols already processed
const vwapPinned = new Map();            // symbol -> row (kept for display)
const VWAP_PIN_MAX = 100;
const VWAP_PIN_TTL_MS = 60 * 60 * 1000;  // 1 hour expiry

// Rank by Gap% then Momentum
function rankGapMomentum(arr){
  return arr.slice().sort((a,b)=>{
    const gA = Math.abs(Number(a.gapPct)||0);
    const gB = Math.abs(Number(b.gapPct)||0);
    if (gA !== gB) return gB - gA;
    const mA = Number(a.score)||0;
    const mB = Number(b.score)||0;
    return mB - mA;
  });
}

// Detect VWAP break condition
function isVWAPBreak(row){
  const price = Number(row?.price);
  const vwap = Number(row?.vwap_5m);
  const volR = Number(row?.volRatio_5m) || 0;
  const score = Number(row?.score) || 0;
  const gap = Math.abs(Number(row?.gapPct) || 0);

  if (!Number.isFinite(price) || !Number.isFinite(vwap) || vwap <= 0) return false;
  if (price <= vwap) return false;   // must be above VWAP
  if (gap < 2) return false;          // minimum gap 2%
  if (volR < 1.2 && score < 60) return false;  // need vol spike OR decent score
  return true;
}

// Auto-add row to VWAP box if qualifies
function maybeAddVWAP(row, fromBox){
  const sym = String(row?.symbol || "").trim().toUpperCase();
  if (!sym || vwapSeen.has(sym)) return false;
  if (!isVWAPBreak(row)) return false;

  vwapSeen.add(sym);
  vwapPinned.set(sym, {
    ...row,
    _from: fromBox,
    _addedAt: Date.now()
  });

  // Prune if too many
  if (vwapPinned.size > VWAP_PIN_MAX){
    const arr = Array.from(vwapPinned.entries()).sort((a,b)=> (a[1]?._addedAt||0) - (b[1]?._addedAt||0));
    const drop = arr.length - VWAP_PIN_MAX;
    for (let i=0;i<drop;i++) vwapPinned.delete(arr[i][0]);
  }

  console.log("🔥 VWAP BREAK:", sym, "from", fromBox);
  ringBell();  // 🔔 ring bell
  return true;
}

