// Ring bell function
function ringBell() {
  try {
    bellAudio.currentTime = 0;
    bellAudio.play().catch(e => {
      console.log("🔕 Bell blocked by browser autoplay policy");
    });
  } catch (e) {
    console.log("🔕 Bell error:", e.message);
  }
}

// Detect new symbols in box results
function detectNewSymbols(boxId, rows) {
  const currentSymbols = new Set(
    rows.map(r => r.symbol).filter(Boolean)
  );

  // Initialize memory for this box if first time
  if (!boxSymbolMemory[boxId]) {
    boxSymbolMemory[boxId] = new Set();
  }

  // Check for new symbols
  let newSymbolsFound = [];
  for (const sym of currentSymbols) {
    if (!boxSymbolMemory[boxId].has(sym)) {
      newSymbolsFound.push(sym);
    }
  }

  // Only ring bell if we have previous data (not first load)
  if (newSymbolsFound.length > 0 && boxSymbolMemory[boxId].size > 0) {
    console.log("New symbols in " + boxId + ":", newSymbolsFound.join(", "));
    ringBell();
    
    // Optional: Show toast notification
    const notificationDiv = document.createElement("div");
    notificationDiv.style.cssText = "position: fixed; top: 80px; right: 20px; background: linear-gradient(135deg, #9b59fe 0%, #00d4ff 100%); color: white; padding: 12px 20px; border-radius: 12px; font-size: 13px; font-weight: 600; z-index: 10000; box-shadow: 0 8px 24px rgba(155, 89, 254, 0.4); animation: slideIn 0.3s ease;";
    const symbolList = newSymbolsFound.slice(0, 3).join(", ") + (newSymbolsFound.length > 3 ? "..." : "");
    notificationDiv.textContent = "\ud83d\udd14 " + newSymbolsFound.length + " new symbol(s): " + symbolList;
    document.body.appendChild(notificationDiv);
    
    setTimeout(() => {
      notificationDiv.style.opacity = "0";
      notificationDiv.style.transition = "opacity 0.3s";
      setTimeout(() => notificationDiv.remove(), 300);
    }, 3000);
  }

  // Update memory
  boxSymbolMemory[boxId] = currentSymbols;
  
  return newSymbolsFound;
}

