// /filter-rsi — RSI Oversold/Overbought Filter
app.get("/filter-rsi", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const mode = String(req.query.mode || "oversold").toLowerCase(); // oversold, overbought, neutral
    const rsiMin = Number(req.query.rsiMin || (mode === "oversold" ? 0 : mode === "overbought" ? 70 : 40));
    const rsiMax = Number(req.query.rsiMax || (mode === "oversold" ? 30 : mode === "overbought" ? 100 : 60));

    // Get universe
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Fetch 5m aggregates and calculate RSI
    const enriched = await mapPool(rows.slice(0, limit * 2), SNAP_CONCURRENCY, async (r) => {
      const a = await fetchAggs5m(r.symbol);
      if (!a.ok || !a.bars || a.bars.length < RSI_LEN + 5) return { ...r, rsi: null };
      
      const barsChrono = [...a.bars].reverse();
      const closes = barsChrono.map(b => n(b?.c)).filter(x => x != null);
      const rsiArr = rsiSeries(closes, RSI_LEN);
      const rsi = rsiArr[rsiArr.length - 1];
      
      return { ...r, rsi: rsi != null ? round2(rsi) : null };
    });

    // Filter by RSI range
    rows = enriched
      .filter(r => r.rsi != null && r.rsi >= rsiMin && r.rsi <= rsiMax)
      .sort((a, b) => {
        if (mode === "oversold") return (a.rsi ?? 100) - (b.rsi ?? 100); // lowest first
        if (mode === "overbought") return (b.rsi ?? 0) - (a.rsi ?? 0); // highest first
        return Math.abs(50 - (a.rsi ?? 50)) - Math.abs(50 - (b.rsi ?? 50)); // closest to 50
      })
      .slice(0, limit);

    res.json({ ok: true, box: "filter-rsi", mode, rsiMin, rsiMax, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/filter-rsi failed", detail: String(e?.message || e) });
  }
});

// /filter-rsi-reversal — RSI Divergence Detection
app.get("/filter-rsi-reversal", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const minRSI = Number(req.query.minRSI || 25); // Oversold threshold
    const maxRSI = Number(req.query.maxRSI || 75); // Overbought threshold

    // Get universe
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Detect RSI reversals
    const enriched = await mapPool(rows.slice(0, limit * 2), SNAP_CONCURRENCY, async (r) => {
      const a = await fetchAggs5m(r.symbol);
      if (!a.ok || !a.bars || a.bars.length < RSI_LEN + 10) return null;
      
      const barsChrono = [...a.bars].reverse();
      const closes = barsChrono.map(b => n(b?.c)).filter(x => x != null);
      const rsiArr = rsiSeries(closes, RSI_LEN);
      
      const rsi = rsiArr[rsiArr.length - 1];
      const rsiPrev = rsiArr[rsiArr.length - 2];
      const rsiPrev2 = rsiArr[rsiArr.length - 3];
      
      if (rsi == null || rsiPrev == null || rsiPrev2 == null) return null;
      
      // Bullish reversal: RSI was oversold (<minRSI) and now rising
      const bullishReversal = rsiPrev < minRSI && rsi > rsiPrev && rsi > rsiPrev2;
      
      // Bearish reversal: RSI was overbought (>maxRSI) and now falling  
      const bearishReversal = rsiPrev > maxRSI && rsi < rsiPrev && rsi < rsiPrev2;
      
      if (!bullishReversal && !bearishReversal) return null;
      
      return { 
        ...r, 
        rsi: round2(rsi), 
        rsiPrev: round2(rsiPrev),
        reversalType: bullishReversal ? "bullish" : "bearish",
        reversalStrength: Math.abs(rsi - rsiPrev)
      };
    });

    rows = enriched
      .filter(r => r != null)
      .sort((a, b) => (b.reversalStrength ?? 0) - (a.reversalStrength ?? 0))
      .slice(0, limit);

    res.json({ ok: true, box: "filter-rsi-reversal", minRSI, maxRSI, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/filter-rsi-reversal failed", detail: String(e?.message || e) });
  }
});

// /filter-macd — MACD Crossover Filter
app.get("/filter-macd", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const mode = String(req.query.mode || "bullish").toLowerCase(); // bullish, bearish

    // Get universe
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Calculate MACD and detect crossovers
    const enriched = await mapPool(rows.slice(0, limit * 2), SNAP_CONCURRENCY, async (r) => {
      const a = await fetchAggs5m(r.symbol);
      if (!a.ok || !a.bars || a.bars.length < Math.max(MACD_SLOW, MACD_SIGNAL) + 5) return null;
      
      const barsChrono = [...a.bars].reverse();
      const closes = barsChrono.map(b => n(b?.c)).filter(x => x != null);
      const macd = macdSeries(closes, MACD_FAST, MACD_SLOW, MACD_SIGNAL);
      
      const idx = closes.length - 1;
      const idxPrev = idx - 1;
      
      const macdNow = macd.macd[idx];
      const signalNow = macd.signal[idx];
      const histNow = macd.hist[idx];
      
      const macdPrev = macd.macd[idxPrev];
      const signalPrev = macd.signal[idxPrev];
      const histPrev = macd.hist[idxPrev];
      
      if (macdNow == null || signalNow == null || histNow == null) return null;
      if (macdPrev == null || signalPrev == null || histPrev == null) return null;
      
      // Bullish crossover: MACD crosses above signal
      const bullishCross = macdPrev <= signalPrev && macdNow > signalNow;
      
      // Bearish crossover: MACD crosses below signal
      const bearishCross = macdPrev >= signalPrev && macdNow < signalNow;
      
      // Filter by mode
      if (mode === "bullish" && !bullishCross) return null;
      if (mode === "bearish" && !bearishCross) return null;
      
      return {
        ...r,
        macd: Number(macdNow.toFixed(4)),
        macdSignal: Number(signalNow.toFixed(4)),
        macdHist: Number(histNow.toFixed(4)),
        crossoverType: bullishCross ? "bullish" : "bearish",
        histogramStrength: Math.abs(histNow)
      };
    });

    rows = enriched
      .filter(r => r != null)
      .sort((a, b) => (b.histogramStrength ?? 0) - (a.histogramStrength ?? 0))
      .slice(0, limit);

    res.json({ ok: true, box: "filter-macd", mode, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/filter-macd failed", detail: String(e?.message || e) });
  }
});

// /filter-ao — Awesome Oscillator Filter  
app.get("/filter-ao", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const mode = String(req.query.mode || "rising").toLowerCase(); // rising, above_zero, both

    // Get universe and attach indicators
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Attach AO indicators
    const enriched = await mapPool(rows.slice(0, limit * 2), SNAP_CONCURRENCY, async (r) => {
      const a = await fetchAggs5m(r.symbol);
      if (!a.ok || !a.bars) return null;
      
      const base = indicatorsFromAggs5m(a.bars);
      const aoData = computeAwesomeOscillatorFrom5mBars(base._bars5m_forAwesomeOscillator || []);
      
      const ao = aoData.ao;
      const aoPrev = aoData.aoPrev;
      
      if (ao == null) return null;
      
      // Apply filters based on mode
      if (mode === "above_zero" && ao <= 0) return null;
      if (mode === "rising" && (aoPrev == null || ao <= aoPrev)) return null;
      if (mode === "both" && (ao <= 0 || aoPrev == null || ao <= aoPrev)) return null;
      
      return { ...r, ao, aoPrev, aoMomentum: aoPrev != null ? ao - aoPrev : null };
    });

    rows = enriched
      .filter(r => r != null)
      .sort((a, b) => (b.ao ?? 0) - (a.ao ?? 0))
      .slice(0, limit);

    res.json({ ok: true, box: "filter-ao", mode, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/filter-ao failed", detail: String(e?.message || e) });
  }
});

// /filter-ema-stack — EMA Bullish/Bearish Stack Filter
app.get("/filter-ema-stack", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const mode = String(req.query.mode || "bullish").toLowerCase(); // bullish, bearish

    // Get universe
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Calculate EMAs
    const enriched = await mapPool(rows.slice(0, limit * 2), SNAP_CONCURRENCY, async (r) => {
      const a = await fetchAggs5m(r.symbol);
      if (!a.ok || !a.bars || a.bars.length < 50) return null;
      
      const barsChrono = [...a.bars].reverse();
      const closes = barsChrono.map(b => n(b?.c)).filter(x => x != null);
      
      const ema9Arr = emaSeries(closes, 9);
      const ema34Arr = emaSeries(closes, 34);
      const ema50Arr = emaSeries(closes, 50);
      
      const idx = closes.length - 1;
      const ema9 = ema9Arr[idx];
      const ema34 = ema34Arr[idx];
      const ema50 = ema50Arr[idx];
      
      if (ema9 == null || ema34 == null || ema50 == null) return null;
      
      // Bullish stack: EMA9 > EMA34 > EMA50
      const bullishStack = ema9 > ema34 && ema34 > ema50;
      
      // Bearish stack: EMA9 < EMA34 < EMA50
      const bearishStack = ema9 < ema34 && ema34 < ema50;
      
      if (mode === "bullish" && !bullishStack) return null;
      if (mode === "bearish" && !bearishStack) return null;
      
      // Calculate spacing between EMAs (tighter = stronger)
      const spacing = Math.abs(ema9 - ema50) / ema50 * 100;
      
      return {
        ...r,
        ema9_5m: round2(ema9),
        ema34_5m: round2(ema34),
        ema50_5m: round2(ema50),
        emaStackType: bullishStack ? "bullish" : "bearish",
        emaSpacing: round2(spacing)
      };
    });

    rows = enriched
      .filter(r => r != null)
      .sort((a, b) => (a.emaSpacing ?? 999) - (b.emaSpacing ?? 999)) // Tighter spacing first
      .slice(0, limit);

    res.json({ ok: true, box: "filter-ema-stack", mode, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/filter-ema-stack failed", detail: String(e?.message || e) });
  }
});

