// /float-turnover — Float Turnover Leaders
app.get("/float-turnover", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const minTurnover = Number(req.query.minTurnover || 5); // Minimum 5% turnover

    // Get universe
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Enrich with float data
    rows = await enrichRowsWithFloat(rows.slice(0, limit * 2));

    // Calculate float turnover %
    rows = rows.map(r => {
      const floatShares = n(r?.floatShares);
      const volume = n(r?.volume);
      const floatTurnoverPct = (floatShares > 0 && volume > 0) ? (volume / floatShares) * 100 : 0;
      return { ...r, floatTurnoverPct: round2(floatTurnoverPct) };
    });

    // Filter and sort
    rows = rows
      .filter(r => r.floatTurnoverPct >= minTurnover)
      .sort((a, b) => (b.floatTurnoverPct ?? 0) - (a.floatTurnoverPct ?? 0))
      .slice(0, limit);

    res.json({ ok: true, box: "float-turnover", minTurnover, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/float-turnover failed", detail: String(e?.message || e) });
  }
});

// /low-float-hot — Low Float Hot Stocks
app.get("/low-float-hot", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 100), 10, 500);
    const maxFloat = Number(req.query.maxFloat || 20); // Max 20M float (in millions)
    const minVolume = Number(req.query.minVolume || 500000); // Min 500K volume
    const minGap = Number(req.query.minGap || 5); // Min 5% gap

    // Get universe
    let out;
    if (ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: limit * 3, session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: limit * 3, sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);
    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Enrich with float and gap data
    rows = await enrichRowsWithFloat(rows.slice(0, limit * 2));
    rows = await enrichRowsWithDailyOpen(rows);

    // Filter low float + high activity
    rows = rows
      .filter(r => {
        const floatM = n(r?.floatShares) / 1_000_000;
        const volume = n(r?.volume) ?? 0;
        const gapPct = Math.abs(n(r?.gapPct) ?? 0);
        
        return floatM > 0 && floatM <= maxFloat && volume >= minVolume && gapPct >= minGap;
      })
      .map(r => {
        const floatM = n(r?.floatShares) / 1_000_000;
        const floatTurnoverPct = (n(r?.floatShares) > 0 && n(r?.volume) > 0) 
          ? (n(r.volume) / n(r.floatShares)) * 100 
          : 0;
        return { ...r, floatM: round2(floatM), floatTurnoverPct: round2(floatTurnoverPct) };
      })
      .sort((a, b) => {
        // Sort by: Gap% → Float Turnover % → Volume
        const gapDiff = Math.abs(b.gapPct ?? 0) - Math.abs(a.gapPct ?? 0);
        if (Math.abs(gapDiff) > 1) return gapDiff;
        const turnoverDiff = (b.floatTurnoverPct ?? 0) - (a.floatTurnoverPct ?? 0);
        if (Math.abs(turnoverDiff) > 1) return turnoverDiff;
        return (b.volume ?? 0) - (a.volume ?? 0);
      })
      .slice(0, limit);

    res.json({ ok: true, box: "low-float-hot", maxFloat, minVolume, minGap, cap, count: rows.length, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/low-float-hot failed", detail: String(e?.message || e) });
  }
});

// ============================================================================
// BOX 2 — /rank-rovl (composite ranking) — 🔒 PRO FEATURE
// GET /rank-rovl?cap=all&limit=120
// Rank = composite score from: ROVL(5m) + FloatTurn% + Gap% + Volume + PriceMove%
// ============================================================================
app.get("/rank-rovl", requireLogin, requireAccess, async (req, res) => {
  try {
    const cap = String(req.query.cap || "all").toLowerCase();
    const limit = clamp(Number(req.query.limit || 120), 10, 500);

    // Build a universe (choose what exists in your script)
    let out;
    if (typeof ENABLE_SNAPSHOT_ALL !== "undefined" && ENABLE_SNAPSHOT_ALL && typeof buildRowsFromSnapshotAll === "function") {
      out = await buildRowsFromSnapshotAll({ cap, limit: Math.max(250, limit * 6), session: null, sortMode: "active" });
    } else if (typeof buildRowsFromMoversUnion === "function") {
      out = await buildRowsFromMoversUnion({ cap, limit: Math.max(250, limit * 6), sortMode: "active" });
    } else {
      return res.status(500).json({ ok: false, error: "No universe builder available for /rank-rovl" });
    }

    if (!out.ok) return res.status(out.status).json(out.body);

    let rows = Array.isArray(out.body?.results) ? out.body.results : [];

    // Ensure float turnover exists
    rows = rows.map(addFloatTurnoverPct);

    // Add compositeRank using norm01
    rows = rows.map((r) => ({ ...r, compositeRank: computeCompositeRankNorm01(r) }));

    rows.sort((a, b) => (n(b.compositeRank) ?? 0) - (n(a.compositeRank) ?? 0));
    rows = rows.slice(0, limit);

    res.json({ ok: true, box: "rank-rovl", cap, results: rows });
  } catch (e) {
    res.status(500).json({ ok: false, error: "/rank-rovl failed", detail: String(e?.message || e) });
  }
});

