// ============================================================================
if (GOOGLE_CLIENT_ID && GOOGLE_CLIENT_SECRET) {
  app.get('/auth/google', (req, res, next) => {
    console.log("🔵 OAUTH START callbackURL =", GOOGLE_CALLBACK_URL);
    
    // 🎯 PRESERVE RETURN URL: Store intended destination for post-login redirect
    const returnUrl = req.query.returnUrl || req.query.return || req.headers.referer || '/ui';
    req.session.returnUrl = returnUrl;
    console.log('🔗 Storing returnUrl in session:', returnUrl);
    
    passport.authenticate('google', { scope: ['profile', 'email'] })(req, res, next);
  });

  app.get('/auth/google/callback', (req, res, next) => {
    console.log("🔴 OAUTH CALLBACK callbackURL =", GOOGLE_CALLBACK_URL);
    console.log("🔍 Query params:", req.query);
    console.log("🔍 Full URL:", req.protocol + '://' + req.get('host') + req.originalUrl);
    console.log("🔍 Session ID before auth:", req.sessionID);
    
    passport.authenticate('google', (err, user, info) => {
      if (err) {
        console.error('❌ OAuth callback error:', err);
        console.error('Error details:', JSON.stringify(err, null, 2));
        return res.redirect('/pricing?error=oauth');
      }
      if (!user) {
        console.error('❌ OAuth callback - no user:', info);
        return res.redirect('/pricing?error=auth_failed');
      }
      
      // CRITICAL: Establish session with req.logIn
      req.logIn(user, (e) => {
        if (e) {
          console.error('❌ req.logIn error:', e);
          console.error('Session error stack:', e.stack);
          return res.redirect('/pricing?error=session');
        }
        console.log('✅ User logged in successfully:', user.email);
        console.log('✅ Session ID after login:', req.sessionID);
        console.log('✅ Session user:', req.user?.id, req.user?.email);
        
        // 🔒 Check if user needs card verification before accessing trial
        const requireCard = String(process.env.REQUIRE_CARD_FOR_TRIAL || "true").toLowerCase() === "true";
        const userTier = String(user?.tier || "").toUpperCase();
        const cardVerified = user?.card_verified === 1;
        
        // Redirect to card verification if:
        // 1. Card verification is required AND
        // 2. User is PENDING_TRIAL (new user who hasn't verified card)
        if (requireCard && userTier === "PENDING_TRIAL" && !cardVerified) {
          console.log('🔒 Redirecting to card verification:', user.email);
          return res.redirect('/verify-card');
        }
        
        // 🎯 REDIRECT TO PRESERVED URL: Use stored returnUrl or default to /ui
        const returnUrl = req.session.returnUrl || '/ui';
        delete req.session.returnUrl; // Clear after use
        console.log('✅ Redirecting to returnUrl:', returnUrl);
        return res.redirect(returnUrl);
      });
    })(req, res, next);
  });

  app.get('/logout', (req, res) => {
    req.logout((err) => {
      if (err) {
        console.error('Logout error:', err);
        return res.redirect('/ui');
      }
      res.redirect('/pricing');
    });
  });
} else {
  // Fallback routes when OAuth is disabled
  app.get('/auth/google', (req, res) => {
    res.status(503).json({ ok: false, error: 'OAuth not configured' });
  });
  
  app.get('/auth/google/callback', (req, res) => {
    res.redirect('/pricing?error=oauth_disabled');
  });
  
  app.get('/logout', (req, res) => {
    res.redirect('/pricing');
  });
}

