app.post("/admin/login", express.urlencoded({ extended: false }), async (req, res) => {
  if (!adminGuard(req, res)) return;
  if (!ADMIN_PASSWORD_HASH) return res.status(500).send("ADMIN_PASSWORD_HASH missing");

  const email = String(req.body?.email || "").trim().toLowerCase();
  const password = String(req.body?.password || "");

  // 👥 Check if email is in admin list
  if (!isAdminEmail(email)) return res.status(401).send("Unauthorized - email not in admin list");
  const ok = await bcrypt.compare(password, ADMIN_PASSWORD_HASH);
  if (!ok) return res.status(401).send("Unauthorized - invalid password");

  // Ensure admin user exists
  let user = await getUserByEmail(email);
  if (!user) {
    const now = Date.now();
    user = await createUser({
      googleId: `admin-${email}`,
      email,
      name: "Admin",
      avatar: null,
      tier: "PRO",
      freeStartAt: now,
      freeUntil: now + (365 * 24 * 60 * 60 * 1000), // 1 year
    });
    // Mark as paid PRO user
    await updateUser(user.id, {
      isPaid: true,
      paidUntil: now + (365 * 24 * 60 * 60 * 1000),
      tier: "PRO"
    });
    user = await getUserById(user.id);
  }

  // IMPORTANT: Create session same as Google login
  req.login(user, (err) => {
    if (err) {
      console.error("Admin req.login error:", err);
      return res.status(500).send("Login failed");
    }

    // ✅ Mark this session as ADMIN and set expiry time
    req.session.isAdmin = true;
    req.session.adminLoginAt = Date.now();
    req.session.adminUserId = user.id; // Store original admin ID for impersonation restore

    console.log("✅ Admin logged in:", user.email);
    return res.redirect("/ui");
  });
});

app.get("/admin/logout", (req, res) => {
  if (!ENABLE_ADMIN_LOGIN) return res.status(404).send("Not found");
  req.logout((err) => {
    if (err) console.error("Admin logout error:", err);
    req.session?.destroy(() => res.redirect("/pricing"));
  });
});

// ============================================================================
// Admin: Session Info (Countdown to auto-logout)
// ============================================================================
app.get("/admin/session", (req, res) => {
  const isAdmin = Boolean(req.session?.isAdmin);
  const at = Number(req.session?.adminLoginAt || 0);
  const now = Date.now();
  const msLeft = isAdmin && at ? Math.max(0, (at + ADMIN_SESSION_TTL_MS) - now) : 0;
  res.json({ ok: true, isAdmin, msLeft });
});

// ============================================================================
// Admin: Impersonate User (Test BASIC/PRO)
// ============================================================================
app.get("/admin/impersonate", requireLogin, requireAdmin, async (req, res) => {
  if (!ENABLE_ADMIN_IMPERSONATE) return res.status(404).send("Not found");

  const email = String(req.query.email || "").trim().toLowerCase();
  if (!email || !email.includes("@")) return res.status(400).send("email required");

  const target = await getUserByEmail(email);
  if (!target) return res.status(404).send("user not found");

  // Save original admin user ID before impersonation (if not already impersonating)
  if (!req.session.adminUserId) {
    req.session.adminUserId = req.user.id;
  }

  req.login(target, (err) => {
    if (err) return res.status(500).send("impersonate failed");
    // Keep admin flag and timestamp so session doesn't expire
    req.session.isAdmin = true;
    console.log(`✅ Admin impersonating: ${target.email}`);
    return res.redirect("/ui?impersonated=1");
  });
});

// Admin: Stop impersonation (restore original admin account)
app.get("/admin/stop-impersonate", requireLogin, async (req, res) => {
  const adminUserId = Number(req.session?.adminUserId || 0);
  
  if (!adminUserId) {
    // No saved admin ID, just redirect to admin login
    return res.redirect("/admin/login");
  }

  // Restore original admin user
  const adminUser = await getUserById(adminUserId);
  if (!adminUser) {
    console.error("⚠️  Admin user not found:", adminUserId);
    return res.redirect("/admin/login");
  }

  req.login(adminUser, (err) => {
    if (err) {
      console.error("Stop impersonate error:", err);
      return res.redirect("/admin/login");
    }
    // Restore admin flags
    req.session.isAdmin = true;
    console.log("✅ Admin restored:", adminUser.email);
    return res.redirect("/ui?admin_restored=1");
  });
});

// ============================================================================
// Admin: Fix FREE14 users with missing free_until
// ============================================================================
app.get("/admin/fix-free14", requireLogin, async (req, res) => {
  try {
    const users = getAllUsers();
    const brokenUsers = users.filter(u => 
      String(u.tier).toUpperCase() === "FREE14" && 
      (!u.free_until || u.free_until === 0)
    );
    
    const fixed = [];
    for (const user of brokenUsers) {
      const createdAt = Number(user.created_at || Date.now());
      const now = Date.now();
      
      // If created more than 14 days ago, give them 14 days from now
      const daysSinceCreation = (now - createdAt) / (24 * 60 * 60 * 1000);
      const freeUntil = daysSinceCreation > 14 
        ? now + (14 * 24 * 60 * 60 * 1000)
        : createdAt + (14 * 24 * 60 * 60 * 1000);
      
      await updateUser(user.id, {
        freeStartAt: createdAt,
        freeUntil: freeUntil
      });
      
      fixed.push({
        id: user.id,
        email: user.email,
        createdAt,
        freeUntil,
        daysRemaining: Math.ceil((freeUntil - now) / (24 * 60 * 60 * 1000))
      });
    }
    
    res.json({
      ok: true,
      message: `Fixed ${fixed.length} FREE14 users`,
      total: users.length,
      broken: brokenUsers.length,
      fixed
    });
  } catch (e) {
    console.error("Fix FREE14 error:", e);
    res.status(500).json({ ok: false, error: String(e?.message || e) });
  }
});

// ============================================================================
// Admin: Unlock/Upgrade User Tier (Grant Premium Access)
// ============================================================================
app.post("/admin/unlock-tier", requireLogin, requireAdmin, express.json(), async (req, res) => {
  try {
    const email = String(req.body?.email || "").trim().toLowerCase();
    const tier = String(req.body?.tier || "PRO").toUpperCase();
    const months = Number(req.body?.months || 12); // Default: 12 months
    
    if (!email || !email.includes("@")) {
      return res.status(400).json({ ok: false, error: "EMAIL_REQUIRED" });
    }
    
    // Validate tier
    const validTiers = ["BASIC", "PRO", "PREMIUM", "TRIAL7"];
    if (!validTiers.includes(tier)) {
      return res.status(400).json({ ok: false, error: "INVALID_TIER", validTiers });
    }
    
    let user = await getUserByEmail(email);
    if (!user) {
      // Create user if doesn't exist
      const now = Date.now();
      user = await createUser({
        googleId: `admin-unlock-${email}`,
        email,
        name: email.split("@")[0],
        avatar: null,
        tier: tier,
        freeStartAt: 0,
        freeUntil: 0,
      });
    }
    
    // Grant paid access
    const now = Date.now();
    const paidUntil = now + (months * 30 * 24 * 60 * 60 * 1000); // months in ms
    
    await updateUser(user.id, {
      tier: tier,
      isPaid: true,
      paidUntil: paidUntil,
      freeUntil: 0 // Clear trial
    });
    
    const updated = await getUserById(user.id);
    const access = computeAccessCountdown(updated);
    
    console.log(`✅ Admin unlocked tier for: ${email} (${tier} for ${months} months)`);
    
    res.json({
      ok: true,
      message: `Tier unlocked: ${tier} for ${months} months`,
      user: {
        email: updated.email,
        tier: access.tier,
        mode: access.mode,
        daysLeft: access.days,
        accessUntil: new Date(access.until).toISOString()
      }
    });
  } catch (e) {
    console.error("Unlock tier error:", e);
    res.status(500).json({ ok: false, error: String(e?.message || e) });
  }
});

// ============================================================================
// Admin: Reset 14-Day Free Trial
// ============================================================================
app.post("/admin/reset-trial", requireLogin, requireAdmin, express.json(), async (req, res) => {
  try {
    const email = String(req.body?.email || "").trim().toLowerCase();
    
    if (!email || !email.includes("@")) {
      return res.status(400).json({ ok: false, error: "EMAIL_REQUIRED" });
    }
    
    const user = await getUserByEmail(email);
    if (!user) {
      return res.status(404).json({ ok: false, error: "USER_NOT_FOUND" });
    }
    
    // Reset trial to 14 days from now
    const now = Date.now();
    const freeUntil = now + (14 * 24 * 60 * 60 * 1000);
    
    await updateUser(user.id, {
      tier: "FREE14",
      freeStartAt: now,
      freeUntil: freeUntil,
      isPaid: false,
      paidUntil: 0
    });
    
    const updated = await getUserById(user.id);
    const access = computeAccessCountdown(updated);
    
    console.log(`✅ Admin reset trial for: ${email}`);
    
    res.json({
      ok: true,
      message: `Trial reset for ${email}`,
      user: {
        email: updated.email,
        tier: access.tier,
        mode: access.mode,
        daysLeft: access.days,
        hoursLeft: access.hours,
        accessUntil: new Date(access.until).toISOString()
      }
    });
  } catch (e) {
    console.error("Reset trial error:", e);
    res.status(500).json({ ok: false, error: String(e?.message || e) });
  }
});

