// ============================================================================
// Saler API — Dashboard and Referral Tracking
// ============================================================================
app.get("/api/saler/:salerId/dashboard", async (req, res) => {
  try {
    const salerId = String(req.params.salerId || "").trim();
    
    if (!salerId) {
      return res.status(400).json({ ok: false, error: "SALER_ID_REQUIRED" });
    }
    
    // Get all customers referred by this saler
    const customers = getUsersBySalerId(salerId);
    
    // Calculate stats
    const totalCustomers = customers.length;
    const activeCustomers = customers.filter(c => c.is_paid === 1).length;
    
    // Calculate monthly revenue (simplified - assumes all active subscriptions)
    // Price mapping: BASIC=$35.99, PRO=$45.99, PREMIUM=$55.99
    const priceMap = { BASIC: 35.99, PRO: 45.99, PREMIUM: 55.99, FREE14: 0 };
    let monthlyRevenue = 0;
    
    const customerData = customers.map(c => {
      const tier = String(c.tier || "FREE14").toUpperCase();
      const revenue = c.is_paid ? (priceMap[tier] || 0) : 0;
      monthlyRevenue += revenue;
      
      return {
        email: c.email,
        tier: tier,
        isPaid: Boolean(c.is_paid),
        createdAt: c.created_at,
        revenue: revenue
      };
    });
    
    // Commission is 65% of monthly revenue (35% to ALGTP LLC for platform operations)
    const estimatedCommission = monthlyRevenue * 0.65;
    
    res.json({
      ok: true,
      salerId,
      totalCustomers,
      activeCustomers,
      monthlyRevenue: monthlyRevenue.toFixed(2),
      estimatedCommission: estimatedCommission.toFixed(2),
      customers: customerData
    });
    
  } catch (e) {
    console.error("Saler dashboard error:", e);
    res.status(500).json({ ok: false, error: "DASHBOARD_LOAD_FAILED", detail: String(e?.message || e) });
  }
});

// ============================================================================
// Stripe Checkout — MULTIPLE PRICING TIERS
// ============================================================================
app.get("/stripe/checkout", requireLogin, async (req, res) => {
  try {
    if (!stripe) return res.redirect("/pricing?error=stripe_not_configured");

    // Get plan from query parameter (default to pro)
    const requestedPlan = String(req.query.plan || "pro").toLowerCase();
    // Scanner Dashboard plans + TradingView Indicator plans
    const validPlans = [
      // Scanner Dashboard (New 5-Tier Structure)
      "trial_495", "basic_3599", "swing_4599", "pro_monthly", "annual_350",
      // Scanner Dashboard (Legacy)
      "basic", "pro", "premium",
      // TradingView Indicators
      "tv_trial", "tv_monthly", "tv_monthly_own", "tv_lifetime", "tv_single_layout",
      // Legacy aliases
      "trial", "monthly", "annual", "monthlytoown", "lifetime"
    ];
    const plan = validPlans.includes(requestedPlan) ? requestedPlan : "pro_monthly";
    
    // Get salerId from query or session
    const salerId = String(req.query.ref || req.session?.salerId || "").trim();
    
    // Store salerId in session for this user
    if (salerId) {
      req.session.salerId = salerId;
      console.log(`💰 Saler referral detected: ${salerId} for user ${req.user?.email}`);
    }
    
    const priceId = PLAN_PRICE_MAP[plan];

    if (!priceId) {
      console.error(`❌ Missing STRIPE priceId for ${plan.toUpperCase()} plan`);
      console.error(`   Available plans:`, Object.keys(PLAN_PRICE_MAP));
      console.error(`   PLAN_PRICE_MAP:`, PLAN_PRICE_MAP);
      return res.redirect(`/pricing?error=price_not_configured&plan=${plan}`);
    }

    // fetch price to detect recurring vs one-time
    let priceObj;
    try {
      priceObj = await stripe.prices.retrieve(priceId);
    } catch (e) {
      console.error("❌ prices.retrieve failed:", e?.message || e);
      return res.redirect("/pricing?error=price_lookup_failed");
    }

    if (!priceObj.active) {
      console.error(`❌ Price inactive: ${priceId}`);
      return res.redirect("/pricing?error=price_inactive");
    }

    const mode = priceObj.recurring ? "subscription" : "payment";

    const session = await stripe.checkout.sessions.create({
      mode,
      customer_email: req.user?.email || undefined,
      line_items: [{ price: priceId, quantity: 1 }],
      success_url: `${APP_URL}/ui?checkout=success&plan=${plan}`,
      cancel_url: `${APP_URL}/pricing?checkout=cancel`,
      allow_promotion_codes: true,
      metadata: {
        userId: req.user?.id || req.user?.email || "unknown",
        plan: plan,
        tier: plan.toUpperCase(),
        salerId: salerId || null,
      },
    });

    // optional analytics log
    try {
      pushEvent({
        ts: Date.now(),
        userId: req.user?.id || req.user?.email || null,
        email: req.user?.email || null,
        tier: getUserTier(req.user),
        event: "checkout_initiated",
        page: "/stripe/checkout",
        featureId: null,
        symbol: null,
        meta: { plan, mode, priceId },
        ip: req.headers["x-forwarded-for"]?.toString()?.split(",")[0]?.trim() || req.socket.remoteAddress || null,
        ua: req.headers["user-agent"] || null,
      });
    } catch {}

    // 🔥 FIX: Use window.open for TradingView embedded browser compatibility
    return res.type("html").send(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="referrer" content="no-referrer">
  <title>Redirecting to Stripe Checkout...</title>
  <style>
    body { font-family: system-ui; display: flex; align-items: center; justify-content: center; height: 100vh; background: #0f0f1e; color: #e8e9f3; }
    .loader { text-align: center; }
    .spinner { border: 3px solid rgba(255,255,255,.1); border-top-color: #9b59fe; border-radius: 50%; width: 40px; height: 40px; animation: spin 1s linear infinite; margin: 0 auto 20px; }
    @keyframes spin { to { transform: rotate(360deg); } }
    .button { margin-top: 20px; padding: 12px 24px; background: #9b59fe; color: white; border: none; border-radius: 8px; cursor: pointer; font-size: 16px; text-decoration: none; display: inline-block; }
    .button:hover { background: #8a4ae6; }
    .note { font-size: 14px; color: #888; margin-top: 10px; }
  </style>
</head>
<body>
  <div class="loader">
    <div class="spinner"></div>
    <p>Opening secure checkout...</p>
    <p class="note">If the checkout doesn't open automatically:</p>
    <button class="button" onclick="openCheckout()">Click here to open checkout</button>
  </div>
  <script>
    const checkoutUrl = ${JSON.stringify(session.url)};
    
    function openCheckout() {
      // Try window.open first (works better in embedded browsers like TradingView)
      const win = window.open(checkoutUrl, '_blank', 'noopener,noreferrer');
      if (win) {
        // Check if popup was blocked
        setTimeout(() => {
          if (!win || win.closed || typeof win.closed === 'undefined') {
            // Popup blocked, fall back to direct navigation
            window.location.href = checkoutUrl;
          }
        }, 100);
      } else {
        // Fallback to direct navigation
        window.location.href = checkoutUrl;
      }
    }
    
    // Auto-open after 1 second
    setTimeout(openCheckout, 1000);
  </script>
</body>
</html>`);
  } catch (e) {
    console.error("❌ Stripe Checkout error:", e?.message || e);
    return res.status(500).send(`Checkout error: ${e?.message || e}`);
  }
});

/**
 * POST /create-checkout
 * Saler Commission System: Create checkout session with saler_id tracking
 * 
 * Body:
 * {
 *   "plan": "55.99",
 *   "saler_id": "david_dao"
 * }
 *
 * Returns:
 * { url: "https://checkout.stripe.com/..." }
 */
app.post("/create-checkout", async (req, res) => {
  try {
    const plan = String(req.body?.plan || "").trim();
    const salerId = String(req.body?.saler_id || "").trim();

    if (!plan || !PRICE_BY_PLAN[plan]) {
      return res.status(400).json({
        error: "Invalid plan. Allowed: " + Object.keys(PRICE_BY_PLAN).join(", "),
      });
    }
    if (!salerId) {
      return res.status(400).json({ error: "Missing saler_id (example: david_dao)" });
    }

    // Validate saler ID (optional - comment out if you want to allow any saler_id)
    if (!isValidSaler(salerId)) {
      console.warn(`⚠️  Unknown saler_id: ${salerId}`);
      // Still allow checkout, just log warning
    }

    const priceId = PRICE_BY_PLAN[plan];

    // Scanner platform only has subscription plans
    const mode = "subscription";

    const session = await stripe.checkout.sessions.create({
      mode,
      line_items: [{ price: priceId, quantity: 1 }],

      // ✅ Store saler_id so webhook commission can read later
      metadata: { saler_id: salerId, plan },

      // Also attach to subscription object if mode=subscription
      ...(mode === "subscription"
        ? { subscription_data: { metadata: { saler_id: salerId, plan } } }
        : {}),

      success_url: `${APP_URL}/success?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${APP_URL}/cancel`,
    });

    return res.json({ url: session.url, plan, priceId, mode });
  } catch (err) {
    console.error("create-checkout error:", err);
    return res.status(500).json({ error: "Failed to create checkout session" });
  }
});

