/**
 * GET /verify-card/confirm - Confirm card verification and start trial
 */
app.get("/verify-card/confirm", requireLogin, async (req, res) => {
  try {
    const setupIntentId = req.query.setup_intent;
    if (!setupIntentId) return res.redirect("/verify-card?error=missing_intent");
    
    const user = req.user;
    
    // Verify the SetupIntent
    const setupIntent = await stripe.setupIntents.retrieve(setupIntentId);
    
    if (setupIntent.status !== 'succeeded') {
      return res.redirect("/verify-card?error=verification_failed");
    }
    
    // Verify it belongs to this user
    if (setupIntent.metadata?.userId !== String(user.id)) {
      return res.redirect("/verify-card?error=invalid_intent");
    }
    
    const now = Date.now();
    const freeUntilMs = now + 14 * 24 * 60 * 60 * 1000; // 14 days
    
    // Update user: mark card verified and start FREE14 trial
    await updateUser(user.id, {
      cardVerified: 1,
      cardVerifiedAt: now,
      tier: "FREE14",
      freeStartAt: now,
      freeUntil: freeUntilMs,
    });
    
    console.log(`✅ Card verified for ${user.email} - FREE14 trial started until ${new Date(freeUntilMs).toISOString()}`);
    
    return res.redirect("/ui?trial_started=1");
  } catch (e) {
    console.error("❌ Verify card confirm error:", e?.message || e);
    return res.redirect("/verify-card?error=confirmation_failed");
  }
});

/**
 * Check if user needs card verification
 */
function needsCardVerification(user) {
  if (!REQUIRE_CARD_FOR_TRIAL) return false;
  if (!user) return false;
  
  // Already verified
  if (user.card_verified === 1) return false;
  
  // Already paid user
  if (user.is_paid === 1) return false;
  
  // Paid tier (BASIC, PRO, PREMIUM)
  const tier = String(user.tier || "").toUpperCase();
  if (["BASIC", "PRO", "PREMIUM"].includes(tier)) return false;
  
  // Admin users skip
  // (handled separately in OAuth callback)
  
  // New FREE14 user without card verification
  if (tier === "FREE14" && user.card_verified !== 1) return true;
  
  return false;
}

