// GET /api/saler/:salerId/dashboard - Dashboard data API
app.get("/api/saler/:salerId/dashboard", async (req, res) => {
  try {
    const { salerId } = req.params;
    
    // Get customers referred by this saler
    const customers = getUsersBySalerId(salerId);
    
    if (!customers) {
      return res.json({
        ok: true,
        salerId,
        totalCustomers: 0,
        activeCustomers: 0,
        monthlyRevenue: "0.00",
        estimatedCommission: "0.00",
        customers: []
      });
    }
    
    const totalCustomers = customers.length;
    const activeCustomers = customers.filter(c => c.is_paid === 1).length;
    
    // Calculate monthly revenue from paid customers (Current 2026 Pricing)
    const prices = {
      // Scanner Platform Tiers (2026)
      'VERIFIED': 4.95,
      'DAYTRADER': 35.99,
      'SWING': 45.99,
      'PRO': 55.99,
      'ANNUAL': 29.17,  // $350/year = $29.17/month
      
      // Legacy tier aliases
      'DAY_TRADER': 35.99,
      'PRO_TRADER': 45.99,
      'INSTITUTIONAL': 55.99,
      'BASIC': 35.99,
      'PREMIUM': 55.99,
      
      // TradingView Indicators (if applicable)
      'TRIAL': 19,
      'MONTHLY': 79,
      'MONTHLY_OWN': 149,
      'LIFETIME': 0  // Lifetime = one-time payment, not monthly
    };
    
    let monthlyRevenue = 0;
    customers.forEach(c => {
      if (c.is_paid === 1 && c.tier) {
        const tier = String(c.tier).toUpperCase();
        monthlyRevenue += prices[tier] || 0;
      }
    });
    
    const estimatedCommission = monthlyRevenue * 0.65; // 65% commission
    
    res.json({
      ok: true,
      salerId,
      totalCustomers,
      activeCustomers,
      monthlyRevenue: monthlyRevenue.toFixed(2),
      estimatedCommission: estimatedCommission.toFixed(2),
      // Referral Links (always included)
      referralUrl: `${APP_URL}/pricing?ref=${salerId}`,
      referralUrlScanner: `${APP_URL}/pricing?ref=${salerId}`,
      referralUrlTV: `${APP_URL}/tv-pricing?ref=${salerId}`,
      customers: customers.map(c => {
        const tier = String(c.tier || 'FREE14').toUpperCase();
        const revenue = (c.is_paid === 1 && prices[tier]) ? prices[tier] : 0;
        return {
          email: c.email,
          tier: c.tier || 'FREE14',
          isPaid: c.is_paid === 1,
          createdAt: c.created_at,
          monthlySpending: revenue.toFixed(2),
          commission: (revenue * 0.65).toFixed(2)
        };
      })
    });
  } catch (error) {
    console.error("[Saler Dashboard API] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

