// POST /api/saler/:salerId/invites/create - Create invite for customer
app.post("/api/saler/:salerId/invites/create", express.json(), (req, res) => {
  try {
    const { salerId } = req.params;
    const { email, tvUsername, expiresInDays } = req.body;
    
    // Validate saler exists
    const saler = getSalerById(salerId);
    if (!saler) {
      return res.status(404).json({ ok: false, error: "Saler not found" });
    }
    
    if (!email) {
      return res.status(400).json({ ok: false, error: "Customer email is required" });
    }
    
    if (!tvUsername) {
      return res.status(400).json({ ok: false, error: "TradingView username is required" });
    }
    
    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({ ok: false, error: "Invalid email format" });
    }
    
    // Check if there's already a pending invite for this email
    const existingInvite = getPendingInviteForEmail(email);
    if (existingInvite) {
      return res.status(400).json({ ok: false, error: "There's already a pending invite for this email" });
    }
    
    // Create invite (product = tradingview for partner-created invites)
    const { invite, token } = createInvite({
      email: email.trim().toLowerCase(),
      tvUsername: tvUsername.trim(),
      product: 'tradingview',
      expiresInDays: expiresInDays || 7,
      invitedBySalerId: salerId
    });
    
    const inviteUrl = `${APP_URL}/invite/accept?token=${token}`;
    
    console.log(`✉️ [Partner ${salerId}] Created invite for: ${email} (TV: ${tvUsername})`);
    
    res.json({
      ok: true,
      message: `Invite created for ${email} (TV: ${tvUsername})`,
      invite: {
        id: invite.id,
        email: invite.email,
        tv_username: invite.tv_username,
        product: invite.product,
        status: invite.status,
        expires_at: invite.expires_at
      },
      inviteUrl,
      instructions: `Send this link to ${email}. They must sign in with this exact email to accept. TV access will be granted to: ${tvUsername}`
    });
  } catch (error) {
    console.error("[Partner Invite Create] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

