// GET /invite/accept - Accept invite page
app.get("/invite/accept", (req, res) => {
  const token = req.query.token;
  
  if (!token) {
    return res.status(400).send(`
      <!DOCTYPE html>
      <html><head><title>Invalid Invite</title>
      <style>body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}</style>
      </head><body><div style="text-align:center;"><h1>❌ Invalid Invite Link</h1><p>No token provided.</p><a href="/" style="color:#9b59fe;">Go Home</a></div></body></html>
    `);
  }
  
  const invite = getInviteByToken(token);
  
  if (!invite) {
    return res.status(404).send(`
      <!DOCTYPE html>
      <html><head><title>Invalid Invite</title>
      <style>body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}</style>
      </head><body><div style="text-align:center;"><h1>❌ Invalid Invite</h1><p>This invite link is invalid or has been revoked.</p><a href="/" style="color:#9b59fe;">Go Home</a></div></body></html>
    `);
  }
  
  if (invite.status !== 'pending') {
    return res.status(400).send(`
      <!DOCTYPE html>
      <html><head><title>Invite ${invite.status}</title>
      <style>body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}</style>
      </head><body><div style="text-align:center;"><h1>ℹ️ Invite Already ${invite.status.charAt(0).toUpperCase() + invite.status.slice(1)}</h1><p>This invite has already been ${invite.status}.</p><a href="/" style="color:#9b59fe;">Go Home</a></div></body></html>
    `);
  }
  
  if (invite.expires_at < Date.now()) {
    return res.status(400).send(`
      <!DOCTYPE html>
      <html><head><title>Invite Expired</title>
      <style>body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}</style>
      </head><body><div style="text-align:center;"><h1>⏰ Invite Expired</h1><p>This invite has expired. Please request a new one.</p><a href="/" style="color:#9b59fe;">Go Home</a></div></body></html>
    `);
  }
  
  // Check if user is logged in
  if (!req.isAuthenticated()) {
    // Store token in session and redirect to login
    req.session.pendingInviteToken = token;
    return res.redirect(`/auth/google?redirect=/invite/accept?token=${token}`);
  }
  
  // Verify email matches
  const userEmail = String(req.user?.email || '').trim().toLowerCase();
  const inviteEmail = String(invite.email).trim().toLowerCase();
  
  if (userEmail !== inviteEmail) {
    return res.status(403).send(`
      <!DOCTYPE html>
      <html><head><title>Email Mismatch</title>
      <style>body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}</style>
      </head><body><div style="text-align:center;"><h1>❌ Email Mismatch</h1><p>This invite is for <strong>${invite.email}</strong>, but you're logged in as <strong>${req.user.email}</strong>.</p><p>Please <a href="/logout" style="color:#9b59fe;">logout</a> and login with the correct email.</p></div></body></html>
    `);
  }
  
  // Accept the invite
  const accepted = acceptInvite(token, req.user.id);
  
  if (!accepted) {
    return res.status(500).send(`
      <!DOCTYPE html>
      <html><head><title>Error</title>
      <style>body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}</style>
      </head><body><div style="text-align:center;"><h1>❌ Error</h1><p>Failed to accept invite. Please try again.</p><a href="/" style="color:#9b59fe;">Go Home</a></div></body></html>
    `);
  }
  
  // Success! Redirect to dashboard
  const productLabel = invite.product === 'both' ? 'Scanner + TradingView' : invite.product === 'scanner' ? 'Scanner Dashboard' : 'TradingView Indicators';
  
  res.send(`
    <!DOCTYPE html>
    <html><head><title>Welcome!</title>
    <style>
      body{font-family:system-ui;background:#0f0f1e;color:#e8e9f3;display:flex;align-items:center;justify-content:center;height:100vh;}
      .success{text-align:center;background:rgba(74,222,128,0.1);border:2px solid rgba(74,222,128,0.4);border-radius:20px;padding:40px;max-width:500px;}
      h1{color:#4ade80;margin-bottom:16px;}
      .btn{display:inline-block;margin-top:20px;padding:14px 28px;background:linear-gradient(135deg,#9b59fe,#4ade80);color:white;text-decoration:none;border-radius:12px;font-weight:700;}
    </style>
    <meta http-equiv="refresh" content="3;url=/ui">
    </head>
    <body>
      <div class="success">
        <h1>✅ Welcome to ALGTP™!</h1>
        <p>Your invite has been accepted.</p>
        <p style="color:#9b59fe;font-weight:600;">Access granted: ${productLabel}</p>
        <a href="/ui" class="btn">🚀 Go to Dashboard</a>
        <p style="margin-top:20px;font-size:13px;color:#6b7280;">Redirecting automatically...</p>
      </div>
    </body>
    </html>
  `);
});

