// ACCESS REQUEST SYSTEM (Public Request → Email Notification → Admin Review)
// ============================================================================

// GET /request-access - Public request access form
app.get("/request-access", (req, res) => {
  res.sendFile(join(__dirname, "public", "request-access.html"));
});

// POST /api/request-access - Submit access request
app.post("/api/request-access", express.json(), async (req, res) => {
  try {
    const { email, name, product, message } = req.body;
    
    if (!email) {
      return res.status(400).json({ ok: false, error: "Email is required" });
    }
    
    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({ ok: false, error: "Invalid email format" });
    }
    
    // Check if already has pending request
    if (hasPendingRequest(email)) {
      return res.status(400).json({ ok: false, error: "You already have a pending request. Please wait for review." });
    }
    
    // Create the request
    const request = createAccessRequest({
      email,
      name: name || null,
      product: product || 'tv_indicators',
      message: message || null
    });
    
    console.log(`📥 [Access Request] New request from: ${email} (product: ${product || 'tv_indicators'})`);
    
    // Send email notification to admin
    if (emailTransporter) {
      try {
        await emailTransporter.sendMail({
          from: SMTP_EMAIL,
          to: ADMIN_NOTIFY_EMAIL,
          subject: `🔔 New Access Request - ${email}`,
          html: `
            <h2>New Access Request</h2>
            <p><strong>Email:</strong> ${email}</p>
            <p><strong>Name:</strong> ${name || '(not provided)'}</p>
            <p><strong>Product:</strong> ${product || 'tv_indicators'}</p>
            <p><strong>Message:</strong> ${message || '(no message)'}</p>
            <p><strong>Time:</strong> ${new Date().toISOString()}</p>
            <hr>
            <p><a href="${APP_URL}/admin/invites">Review in Admin Panel</a></p>
          `
        });
        console.log(`📧 Email notification sent to: ${ADMIN_NOTIFY_EMAIL}`);
      } catch (emailErr) {
        console.error("⚠️ Failed to send email notification:", emailErr.message);
        // Don't fail the request if email fails
      }
    } else {
      console.log("⚠️ Email not configured - admin notification skipped");
    }
    
    res.json({
      ok: true,
      message: "Your access request has been submitted. We'll review it shortly and get back to you.",
      requestId: request.id
    });
  } catch (error) {
    console.error("[Access Request] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

