// POST /api/admin/access-requests/:id/approve - Approve request (creates invite)
app.post("/api/admin/access-requests/:id/approve", requireLogin, requireAdmin, express.json(), async (req, res) => {
  try {
    const id = Number(req.params.id);
    const { adminNotes, expiresInDays } = req.body;
    
    const request = getAccessRequestById(id);
    if (!request) {
      return res.status(404).json({ ok: false, error: "Request not found" });
    }
    
    if (request.status !== 'pending') {
      return res.status(400).json({ ok: false, error: `Request already ${request.status}` });
    }
    
    // Approve the request
    const approved = approveAccessRequest(id, req.user?.id || null, adminNotes || null);
    
    // Create an invite for the user
    const { invite, token } = createInvite({
      email: request.email,
      product: request.product || 'tv_indicators',
      expiresInDays: expiresInDays || 7,
      invitedByAdminId: req.user?.id || null
    });
    
    const inviteUrl = `${APP_URL}/invite/accept?token=${token}`;
    
    console.log(`✅ [Admin] Approved access request #${id} for: ${request.email}`);
    console.log(`   Invite created: ${inviteUrl}`);
    
    res.json({
      ok: true,
      message: "Request approved and invite created",
      request: approved,
      invite,
      inviteUrl
    });
  } catch (error) {
    console.error("[Admin Approve Request] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

// POST /api/admin/access-requests/:id/reject - Reject request
app.post("/api/admin/access-requests/:id/reject", requireLogin, requireAdmin, express.json(), async (req, res) => {
  try {
    const id = Number(req.params.id);
    const { adminNotes } = req.body;
    
    const request = getAccessRequestById(id);
    if (!request) {
      return res.status(404).json({ ok: false, error: "Request not found" });
    }
    
    if (request.status !== 'pending') {
      return res.status(400).json({ ok: false, error: `Request already ${request.status}` });
    }
    
    // Reject the request
    const rejected = rejectAccessRequest(id, req.user?.id || null, adminNotes || null);
    
    console.log(`❌ [Admin] Rejected access request #${id} for: ${request.email}`);
    
    res.json({
      ok: true,
      message: "Request rejected",
      request: rejected
    });
  } catch (error) {
    console.error("[Admin Reject Request] Error:", error);
    res.status(500).json({ ok: false, error: error.message });
  }
});

