// ============================================================================
// /me — User Info Endpoint (for Feature Toggle System)
// ============================================================================
app.get("/me", requireLogin, (req, res) => {
  const u = req.user;
  
  // 🔑 ADMIN BYPASS: Check if user is admin first
  const userEmail = String(u?.email || "").trim().toLowerCase();
  const isAdmin = isAdminEmail(userEmail);
  
  const access = isAdmin 
    ? { mode: "ADMIN", tier: "ADMIN", until: 0, msLeft: 0, totalHours: 0, days: 0, hours: 0 }
    : computeAccessCountdown(u);

  // ✅ PROPER GATING: FREE14 active = ALL boxes, EXPIRED = null (lock all)
  // - ADMIN: null (full access, no checks)
  // - PAID: null (all access)
  // - FREE (trial active): ALL box IDs (unlock all during trial)
  // - EXPIRED: null (will be locked by requireAccess)
  let allowedBoxes = null;
  let boxesLocked = false;
  
  if (access.mode === "ADMIN") {
    // Admin → full access, no restrictions
    allowedBoxes = null;
    boxesLocked = false;
  } else if (access.mode === "FREE") {
    // FREE14 trial active → return ALL box IDs
    allowedBoxes = "ALL"; // UI will interpret this as all boxes
    boxesLocked = false;
  } else if (access.mode === "PAID") {
    // Paid user → all access
    allowedBoxes = null;
    boxesLocked = false;
  } else {
    // EXPIRED → no access (API will block via requireAccess)
    allowedBoxes = [];
    boxesLocked = true;
  }

  // Get tier limits
  const limits = getTierLimits(access.tier);

  res.json({
    ok: true,
    email: u?.email || null,
    name: u?.name || null,
    avatar: u?.avatar || null,

    tier: access.tier,
    tierLabel: limits.label,
    mode: access.mode,                 // PAID | FREE | EXPIRED
    accessUntil: access.until,
    msLeft: access.msLeft,
    daysLeft: access.days,
    hoursLeft: access.hours,
    totalHoursLeft: access.totalHours, // dùng cho color thresholds

    // ✅ PROPER: FREE14 active = ALL, EXPIRED = [], PAID = null
    allowedBoxes: allowedBoxes,
    boxesLocked: boxesLocked,
    isPaid: access.mode === "PAID",
    paidUntil: access.mode === "PAID" ? access.until : 0,
    
    // 🎯 Tier limits
    maxScanner: limits.maxScanner,
    trialActive: access.mode === "FREE",
    trialEndsAt: access.mode === "FREE" ? access.until : null,
  });
});

