// ============================================================================
// SECTION 13.5 — Agent Bridge Relay (Reverse Tunnel)
// ============================================================================
const agentBridgeEnabled = String(process.env.ENABLE_AGENT_BRIDGE || "true").toLowerCase() === "true";
const agentSessions = new Map(); // sessionId -> {ws, token, connectedAt, authenticated}
const clientConnections = new Map(); // sessionId -> Set of client WebSockets

function generateSessionId() {
  return `agent-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
}

function validateBridgeToken(token) {
  // Allow any pair token format: ALGTP-PAIR-XXXX-XXXXXXXX
  return /^ALGTP-PAIR-[A-Z0-9]{4}-[A-Z0-9]{8}$/i.test(token);
}

function handleAgentBridgeConnection(ws, request) {
  const sessionId = generateSessionId();
  const agentInfo = {
    ws,
    sessionId,
    connectedAt: Date.now(),
    authenticated: false,
    token: null
  };
  
  console.log(`[Agent Bridge] Agent connecting: ${sessionId}`);
  
  ws.on('message', (data) => {
    try {
      const msg = JSON.parse(data.toString());
      
      // Handle authentication
      if (msg.type === 'auth') {
        if (validateBridgeToken(msg.token)) {
          agentInfo.authenticated = true;
          agentInfo.token = msg.token;
          agentSessions.set(sessionId, agentInfo);
          ws.send(JSON.stringify({ type: 'auth:success', sessionId }));
          console.log(`[Agent Bridge] Agent authenticated: ${sessionId}`);
        } else {
          ws.send(JSON.stringify({ type: 'auth:failed', error: 'Invalid token format' }));
          ws.close();
        }
        return;
      }
      
      if (!agentInfo.authenticated) {
        ws.send(JSON.stringify({ type: 'error', message: 'Not authenticated' }));
        return;
      }
      
      // Relay message to all connected clients for this session
      const clients = clientConnections.get(sessionId);
      if (clients && clients.size > 0) {
        clients.forEach(clientWs => {
          if (clientWs.readyState === 1) {
            clientWs.send(data);
          }
        });
      }
    } catch (e) {
      console.error('[Agent Bridge] Error handling agent message:', e);
    }
  });
  
  ws.on('close', () => {
    console.log(`[Agent Bridge] Agent disconnected: ${sessionId}`);
    agentSessions.delete(sessionId);
    // Notify all clients
    const clients = clientConnections.get(sessionId);
    if (clients) {
      clients.forEach(clientWs => {
        if (clientWs.readyState === 1) {
          clientWs.send(JSON.stringify({ type: 'agent:disconnected' }));
          clientWs.close();
        }
      });
      clientConnections.delete(sessionId);
    }
  });
  
  ws.on('error', (err) => {
    console.error(`[Agent Bridge] Agent error: ${sessionId}`, err.message);
  });
}

function handleClientBridgeConnection(ws, request) {
  const url = new URL(request.url, `http://${request.headers.host}`);
  const sessionId = url.searchParams.get('session');
  
  if (!sessionId) {
    ws.send(JSON.stringify({ type: 'error', message: 'Session ID required' }));
    ws.close();
    return;
  }
  
  const agent = agentSessions.get(sessionId);
  if (!agent || !agent.authenticated) {
    ws.send(JSON.stringify({ type: 'error', message: 'Agent session not found or not authenticated' }));
    ws.close();
    return;
  }
  
  // Add client to session
  if (!clientConnections.has(sessionId)) {
    clientConnections.set(sessionId, new Set());
  }
  clientConnections.get(sessionId).add(ws);
  
  console.log(`[Agent Bridge] Client connected to session: ${sessionId}`);
  ws.send(JSON.stringify({ type: 'connected', sessionId }));
  
  ws.on('message', (data) => {
    // Relay message to agent
    if (agent.ws.readyState === 1) {
      agent.ws.send(data);
    }
  });
  
  ws.on('close', () => {
    console.log(`[Agent Bridge] Client disconnected from session: ${sessionId}`);
    const clients = clientConnections.get(sessionId);
    if (clients) {
      clients.delete(ws);
      if (clients.size === 0) {
        clientConnections.delete(sessionId);
      }
    }
  });
  
  ws.on('error', (err) => {
    console.error(`[Agent Bridge] Client error: ${sessionId}`, err.message);
  });
}

// API endpoint to list active agent sessions
app.get("/api/agent-bridge/sessions", (req, res) => {
  if (!agentBridgeEnabled) {
    return res.json({ ok: false, error: "Agent bridge disabled" });
  }
  
  const sessions = Array.from(agentSessions.entries())
    .filter(([_, agent]) => agent.authenticated)
    .map(([sessionId, agent]) => ({
      sessionId,
      connectedAt: agent.connectedAt,
      uptime: Date.now() - agent.connectedAt,
      clientCount: clientConnections.get(sessionId)?.size || 0
    }));
  
  res.json({ ok: true, sessions, count: sessions.length });
});

// API endpoint for bridge status (debugging)
app.get("/api/agent-bridge/status", (req, res) => {
  res.json({
    ok: true,
    enabled: agentBridgeEnabled,
    agentCount: agentSessions.size,
    authenticatedAgentCount: Array.from(agentSessions.values()).filter(a => a.authenticated).length,
    clientCount: Array.from(clientConnections.values()).reduce((sum, set) => sum + set.size, 0),
    sessions: Array.from(agentSessions.entries())
      .map(([sessionId, agent]) => ({
        sessionId,
        authenticated: agent.authenticated,
        connectedAt: agent.connectedAt,
        uptime: Date.now() - agent.connectedAt,
        clientCount: clientConnections.get(sessionId)?.size || 0
      }))
  });
});

// ============================================================================
// SECTION 14 — Start WebSockets + Listen
// ============================================================================
startHaltWebSocket();
startAMWebSocket();

// Helper function to try starting server with port fallback
function startServer(port, maxAttempts = 10) {
  // Create HTTP server to attach WebSocket
  const httpServer = createServer(app);
  
  // Initialize Agent Bridge WebSocket Server
  if (agentBridgeEnabled) {
    const wss = new WebSocketServer({ noServer: true });
    
    httpServer.on('upgrade', (request, socket, head) => {
      const pathname = new URL(request.url, `http://${request.headers.host}`).pathname;
      
      if (pathname === '/agent-bridge') {
        wss.handleUpgrade(request, socket, head, (ws) => {
          handleAgentBridgeConnection(ws, request);
        });
      } else if (pathname === '/agent-client') {
        wss.handleUpgrade(request, socket, head, (ws) => {
          handleClientBridgeConnection(ws, request);
        });
      } else {
        socket.destroy();
      }
    });
    
    console.log('✅ Agent Bridge enabled - agents can connect via /agent-bridge');
  }
  
  const server = httpServer.listen(port)
    .on('listening', () => {
      const actualPort = server.address().port;
      const renderUrl =
        process.env.RENDER_EXTERNAL_URL ||               
        process.env.PUBLIC_URL ||                        
        "";

      const base = renderUrl
        ? renderUrl.replace(/\/+$/, "")
        : `http://localhost:${actualPort}`;

      console.log(`\n✅ ${BRAND.legal} running`);
      if (actualPort !== PORT) {
        console.log(`⚠️  Port ${PORT} was in use, using port ${actualPort} instead`);
      }
      console.log(`🚀 UI: ${base}/ui`);
      console.log(`📈 Mini chart: ${base}/mini-chart?symbol=AAPL&tf=1`);
      console.log(`⛔ Halts: ${base}/halts`);
      console.log(`📌 Movers Premarket: ${base}/movers-premarket?limit=50`);
      console.log(`📌 Movers After-hours: ${base}/movers-afterhours?limit=50`);
      console.log(`ℹ️ API: ${base}/api`);
      console.log("");
      
      // Memory monitoring - detect leaks (logs every 10 seconds)
      setInterval(() => {
        const m = process.memoryUsage();
        console.log("[mem]", {
          rss: (m.rss/1024/1024).toFixed(0)+"MB",
          heapUsed: (m.heapUsed/1024/1024).toFixed(0)+"MB",
          heapTotal: (m.heapTotal/1024/1024).toFixed(0)+"MB",
          ext: (m.external/1024/1024).toFixed(0)+"MB",
        });
      }, 10000);
    })
    .on('error', (err) => {
      if (err.code === 'EADDRINUSE') {
        const nextPort = port + 1;
        if (maxAttempts > 1) {
          console.log(`❌ Port ${port} is in use, trying ${nextPort}...`);
          server.close();
          startServer(nextPort, maxAttempts - 1);
        } else {
          console.error(`\n❌ Unable to find an available port after multiple attempts.`);
          console.error(`💡 To fix: Kill the existing process or specify a different PORT in .env\n`);
          console.error(`   Find process: lsof -ti:${PORT}`);
          console.error(`   Kill process: kill -9 $(lsof -ti:${PORT})\n`);
          process.exit(1);
        }
      } else {
        console.error(`\n❌ Server error:`, err.message);
        process.exit(1);
      }
    });
}

startServer(PORT);
